// ============================================================================
//  SRStoreBackend — Storage Adapter Abstraction
// ============================================================================
// SRStore의 sync surface(get/getRef/set/update/delete/keys)는 절대 불변.
// 백엔드는 async init/persistKeys/listKeys/removeKey/clear만 책임.
// 캐시 일관성은 SRStore가 단독 소유 (백엔드는 무상태).
// 두 구현:
//   - ScriptStateBackend: 기존 chat.scriptstate (Risuai.setChatToIndex 호출 → 재렌더)
//   - PluginStorageBackend: Risuai.getLocalPluginStorage() (IndexedDB, 재렌더 0)
// ============================================================================

class SRStoreBackend {
  get name() { throw new Error('SRStoreBackend.name: abstract'); }
  async init() { throw new Error('SRStoreBackend.init: abstract'); }
  async persistKeys(_map) { throw new Error('SRStoreBackend.persistKeys: abstract'); }
  async listKeys() { throw new Error('SRStoreBackend.listKeys: abstract'); }
  async removeKey(_key) { throw new Error('SRStoreBackend.removeKey: abstract'); }
  async clear() { throw new Error('SRStoreBackend.clear: abstract'); }
  bindChat(_charIdx, _chatIdx) { /* no-op default */ }
}

// ----------------------------------------------------------------------------
//  ScriptStateBackend — chat.scriptstate 기존 동작 캡슐화
// ----------------------------------------------------------------------------
// prefix: $__sr:
// write: Risuai.setChatToIndex (RisuAI 채팅 UI 전체 재렌더 트리거)
// readonly 모드: PSB 모드 진입 후 SS write 0회 보장을 위해.
//   persistKeys가 throw. 단 _writeWhitelist 백도어는 'sr:chatId:v1' 한 키만 허용.
// ----------------------------------------------------------------------------

const SS_PREFIX = '$__sr:';
const SS_WHITELIST_KEY = 'sr:chatId:v1';

class ScriptStateBackend extends SRStoreBackend {
  constructor(charIdx, chatIdx, opts = {}) {
    super();
    this._charIdx = charIdx;
    this._chatIdx = chatIdx;
    this._readonly = !!opts.readonly;
  }

  get name() { return 'scriptstate'; }

  bindChat(charIdx, chatIdx) {
    this._charIdx = charIdx;
    this._chatIdx = chatIdx;
  }

  async init() {
    if (this._charIdx == null || this._charIdx < 0 ||
        this._chatIdx == null || this._chatIdx < 0) {
      throw new Error('ScriptStateBackend.init: invalid char/chat index');
    }
    const chat = await Risuai.getChatFromIndex(this._charIdx, this._chatIdx);
    if (!chat) throw new Error('ScriptStateBackend.init: failed to load chat');

    const out = {};
    const ss = chat.scriptstate || {};
    for (const [fullKey, raw] of Object.entries(ss)) {
      if (!fullKey.startsWith(SS_PREFIX)) continue;
      const key = fullKey.slice(SS_PREFIX.length);
      try {
        out[key] = JSON.parse(raw);
      } catch (_) {
        // 손상된 항목 skip — 다른 키는 정상 로드 유지.
      }
    }
    return out;
  }

  async persistKeys(map) {
    if (this._readonly) {
      throw new Error('ScriptStateBackend.persistKeys: backend is read-only (PSB mode active)');
    }
    return this._persistInternal(map);
  }

  // Backdoor: PSB 모드에서도 chatId 갱신 같은 정당한 SS write만 허용.
  // 'sr:chatId:v1' 외 다른 키는 throw.
  async _writeWhitelist(key, val) {
    if (key !== SS_WHITELIST_KEY) {
      throw new Error(`ScriptStateBackend._writeWhitelist: key '${key}' is not whitelisted (only '${SS_WHITELIST_KEY}')`);
    }
    return this._persistInternal({ [key]: val });
  }

  async _persistInternal(map) {
    const chat = await Risuai.getChatFromIndex(this._charIdx, this._chatIdx);
    if (!chat) throw new Error('ScriptStateBackend.persistKeys: failed to load chat');
    chat.scriptstate = chat.scriptstate || {};

    for (const [key, val] of Object.entries(map)) {
      const fullKey = `${SS_PREFIX}${key}`;
      if (val === undefined) {
        delete chat.scriptstate[fullKey];
      } else {
        chat.scriptstate[fullKey] = JSON.stringify(val);
      }
    }

    await Risuai.setChatToIndex(this._charIdx, this._chatIdx, chat);
  }

  async listKeys() {
    const chat = await Risuai.getChatFromIndex(this._charIdx, this._chatIdx);
    if (!chat || !chat.scriptstate) return [];
    const keys = [];
    for (const fullKey of Object.keys(chat.scriptstate)) {
      if (fullKey.startsWith(SS_PREFIX)) keys.push(fullKey.slice(SS_PREFIX.length));
    }
    return keys;
  }

  async removeKey(key) {
    return this.persistKeys({ [key]: undefined });
  }

  async clear() {
    const keys = await this.listKeys();
    if (keys.length === 0) return;
    const map = {};
    for (const k of keys) map[k] = undefined;
    return this.persistKeys(map);
  }
}

// ----------------------------------------------------------------------------
//  PluginStorageBackend — Risuai.getLocalPluginStorage (IndexedDB/localforage)
// ----------------------------------------------------------------------------
// prefix: srdata:{chatId}:
// chatId 필수 (chicken-and-egg는 SS의 sr:chatId:v1 anchor로 해결).
// listKeys는 자기 chatId prefix 매칭만 — 다른 chat 데이터/srimg 미접근.
// write가 setChatToIndex 미경유 → 채팅 UI 재렌더 0회 (본 PR의 핵심 동기).
// ----------------------------------------------------------------------------

const PSB_PREFIX = 'srdata:';

class PluginStorageBackend extends SRStoreBackend {
  constructor(chatId, storage = null) {
    super();
    if (!chatId) throw new Error('PluginStorageBackend: chatId required');
    this._chatId = chatId;
    this._prefix = `${PSB_PREFIX}${chatId}:`;
    this._storage = storage;
  }

  get name() { return 'pluginstorage'; }

  async _store() {
    if (!this._storage) {
      if (!Risuai.getLocalPluginStorage) {
        throw new Error('PluginStorageBackend: Risuai.getLocalPluginStorage unavailable');
      }
      this._storage = Risuai.getLocalPluginStorage();
    }
    return this._storage;
  }

  async init() {
    const store = await this._store();
    const allKeys = await store.keys();
    const out = {};
    for (const fullKey of allKeys) {
      if (typeof fullKey !== 'string' || !fullKey.startsWith(this._prefix)) continue;
      const key = fullKey.slice(this._prefix.length);
      try {
        const raw = await store.getItem(fullKey);
        if (raw == null) continue;
        out[key] = typeof raw === 'string' ? JSON.parse(raw) : raw;
      } catch (e) {
        // 손상된 키 skip — 나머지 정상 로드.
        console.warn(`[sns_nai] PSB.init: failed to read '${fullKey}': ${e.message}`);
      }
    }
    return out;
  }

  async persistKeys(map) {
    const store = await this._store();
    const errors = [];
    for (const [key, val] of Object.entries(map)) {
      const fullKey = `${this._prefix}${key}`;
      try {
        if (val === undefined) {
          await store.removeItem(fullKey);
        } else {
          await store.setItem(fullKey, JSON.stringify(val));
        }
      } catch (e) {
        errors.push({ key, error: e.message });
      }
    }
    if (errors.length > 0) {
      const summary = errors.map(e => `${e.key}: ${e.error}`).join('; ');
      throw new Error(`PluginStorageBackend.persistKeys: ${errors.length} failure(s) [${summary}]`);
    }
  }

  async listKeys() {
    const store = await this._store();
    const allKeys = await store.keys();
    const out = [];
    for (const fullKey of allKeys) {
      if (typeof fullKey === 'string' && fullKey.startsWith(this._prefix)) {
        out.push(fullKey.slice(this._prefix.length));
      }
    }
    return out;
  }

  async removeKey(key) {
    const store = await this._store();
    await store.removeItem(`${this._prefix}${key}`);
  }

  async clear() {
    const keys = await this.listKeys();
    if (keys.length === 0) return;
    const store = await this._store();
    const errors = [];
    for (const key of keys) {
      try {
        await store.removeItem(`${this._prefix}${key}`);
      } catch (e) {
        errors.push({ key, error: e.message });
      }
    }
    if (errors.length > 0) {
      const summary = errors.map(e => `${e.key}: ${e.error}`).join('; ');
      throw new Error(`PluginStorageBackend.clear: ${errors.length} failure(s) [${summary}]`);
    }
  }
}

// ============================================================================
//  SRStore — chatVar Storage with In-Memory Cache + Debounced Flush
// ============================================================================

class SRStore {
  // backend: SRStoreBackend | null
  //   null이면 init()에서 ScriptStateBackend(charIdx, chatIdx)를 자동 생성한다.
  //   호출자 코드는 시그니처를 모르므로 backend 인자는 부트스트랩 단계에서만 사용.
  constructor(backend = null) {
    this._cache = {};
    this._dirty = new Set();
    this._flushTimer = null;
    this._flushPromise = null;
    this._charIdx = null;
    this._chatIdx = null;
    this._rev = 0;
    this._backend = backend;
    this._readonly = false;
    this._setQueue = [];
    this._backendSwapInProgress = false;
  }

  async init() {
    this._charIdx = await Risuai.getCurrentCharacterIndex();
    this._chatIdx = await Risuai.getCurrentChatIndex();
    if (this._charIdx == null || this._charIdx < 0 ||
        this._chatIdx == null || this._chatIdx < 0) {
      throw new Error('No active character/chat');
    }

    if (!this._backend) {
      this._backend = new ScriptStateBackend(this._charIdx, this._chatIdx);
    } else {
      // 기존 백엔드에 좌표만 다시 바인딩 (PSB는 no-op).
      this._backend.bindChat?.(this._charIdx, this._chatIdx);
    }

    const loaded = await this._backend.init();
    for (const [k, v] of Object.entries(loaded || {})) {
      this._cache[k] = v;
    }

    const meta = this._cache['meta'] || { rev: 0 };
    this._rev = meta.rev || 0;
  }

  // ---- sync surface — 시그니처 절대 불변 ---------------------------------

  get(key) {
    const val = this._cache[key];
    if (val === undefined || val === null) return null;
    return JSON.parse(JSON.stringify(val));
  }

  getRef(key) {
    const val = this._cache[key];
    return val === undefined || val === null ? null : val;
  }

  set(key, value, opts) {
    if (this._readonly && !(opts && opts._migrator)) {
      this._setQueue.push([key, value, opts]);
      return;
    }
    this._cache[key] = JSON.parse(JSON.stringify(value));
    this._dirty.add(key);
    if (opts && opts.critical) {
      return this.flush();
    }
    this._scheduleFlush();
  }

  update(key, fn) {
    const current = this.get(key);
    const updated = fn(current);
    if (updated !== undefined) {
      this.set(key, updated);
    }
    return updated;
  }

  updateCritical(key, fn) {
    const current = this.get(key);
    const updated = fn(current);
    if (updated !== undefined) {
      return this.set(key, updated, { critical: true });
    }
  }

  delete(key) {
    if (this._readonly) {
      this._setQueue.push([key, undefined, { _delete: true }]);
      return;
    }
    delete this._cache[key];
    this._dirty.add(key);
    this._scheduleFlush();
  }

  keys() {
    return Object.keys(this._cache);
  }

  // ---- async surface ------------------------------------------------------

  _scheduleFlush() {
    if (this._flushTimer) return;
    this._flushTimer = setTimeout(() => this.flush(), 500);
  }

  async flush() {
    if (this._flushTimer) {
      clearTimeout(this._flushTimer);
      this._flushTimer = null;
    }

    // swap 진행 중이면 swap 완료까지 대기. swap 완료 후 readonly가 풀리고
    // _setQueue가 비워지며 다시 _scheduleFlush가 걸리므로 여기서는 즉시 반환.
    if (this._backendSwapInProgress) {
      // busy-wait 대신 한 번만 양보. 호출자 코드가 다시 flush를 부르도록 유도.
      return;
    }

    if (this._dirty.size === 0) {
      if (this._flushPromise) await this._flushPromise;
      return;
    }

    if (this._flushPromise) {
      await this._flushPromise;
      if (this._dirty.size > 0) return this.flush();
      return;
    }

    const snapshot = new Set(this._dirty);
    this._dirty = new Set();

    this._flushPromise = (async () => {
      try {
        this._rev++;
        this._cache['meta'] = { ...(this._cache['meta'] || {}), rev: this._rev };
        snapshot.add('meta');

        const backend = this._backend;
        if (!backend) {
          for (const k of snapshot) this._dirty.add(k);
          return;
        }

        const map = {};
        for (const key of snapshot) {
          if (key in this._cache) {
            map[key] = this._cache[key];
          } else {
            map[key] = undefined; // delete
          }
        }

        await backend.persistKeys(map);
      } catch (e) {
        for (const k of snapshot) this._dirty.add(k);
        console.error('[sns_nai] Flush error:', e.message);
      }
    })();

    await this._flushPromise;
    this._flushPromise = null;

    if (this._dirty.size > 0) {
      this._scheduleFlush();
    }
  }

  // ---- backend swap (migration용) ----------------------------------------
  // 호출자: SRMigrator / 디버그 도구만 사용. 일반 호출 경로 없음.
  // 절차:
  //   1) 진행 중 flush 종료 대기
  //   2) 남은 dirty를 구 backend로 마지막 flush (이미 swap 직전 마이그레이터가
  //      _cache.keys() vs dst.listKeys() 차이를 메꿨다고 가정)
  //   3) backend 교체 + 좌표 재바인딩
  //   4) _readonly 해제 + _setQueue 비우기 → set/delete 재호출 (새 backend로 향함)
  async _swapBackend(newBackend) {
    if (this._backendSwapInProgress) {
      throw new Error('SRStore._swapBackend: another swap is already in progress');
    }
    if (!newBackend) {
      throw new Error('SRStore._swapBackend: newBackend required');
    }
    this._backendSwapInProgress = true;
    try {
      if (this._flushTimer) {
        clearTimeout(this._flushTimer);
        this._flushTimer = null;
      }
      if (this._flushPromise) {
        try { await this._flushPromise; } catch (_) {}
      }

      // 백엔드 교체. 캐시는 그대로 — 마이그레이터가 이미 dst에 mirror 완료.
      this._backend = newBackend;
      this._backend.bindChat?.(this._charIdx, this._chatIdx);

      // readonly 해제 후 큐 비우기. set/delete는 sync API라 await 불필요.
      this._readonly = false;
      const queue = this._setQueue;
      this._setQueue = [];
      for (const [key, value, opts] of queue) {
        if (opts && opts._delete) {
          this.delete(key);
        } else {
          this.set(key, value, opts);
        }
      }
    } finally {
      this._backendSwapInProgress = false;
    }
  }
}

// ============================================================================
//  SRMigrator — SS → PSB Migration (flag-last, PSB-side state)
// ============================================================================
// 단계: prep → enumerate → mirror(청크 20) → verify → flag → swap → done
// 보장:
//   - SS write 0회 (enumerate read만). 마이그레이션 도중 SR.flush는 store._readonly=true로
//     큐잉되며 SS persist가 발생하지 않음.
//   - srmig:state:v1는 PSB에 매 청크 persist (재개 anchor).
//   - srmig:done:v1는 swap 직전 PSB에 박음 (flag-last).
//   - verify mismatch는 failed 기록만, rollback 금지.
//   - swap 직전 _cache.keys() vs dst.listKeys() 차이 final mirror.
// ============================================================================

const SRMIG_STATE_KEY = 'srmig:state:v1';
const SRMIG_DONE_KEY = 'srmig:done:v1';
const SRMIG_CHUNK_SIZE = 20;

class SRMigrator {
  constructor({ store, srcBackend, dstBackend, chatId, resumeFrom = null, onProgress = null }) {
    if (!store) throw new Error('SRMigrator: store required');
    if (!srcBackend) throw new Error('SRMigrator: srcBackend required');
    if (!dstBackend) throw new Error('SRMigrator: dstBackend required');
    if (!chatId) throw new Error('SRMigrator: chatId required');
    this.store = store;
    this.src = srcBackend;
    this.dst = dstBackend;
    this.chatId = chatId;
    this.onProgress = typeof onProgress === 'function' ? onProgress : () => {};
    this.cancelled = false;
    this._running = false;
    this._promise = null;

    const now = Date.now();
    this.state = resumeFrom && resumeFrom.chatId === chatId ? {
      phase: resumeFrom.phase || 'prep',
      chatId,
      total: resumeFrom.total || 0,
      completed: Array.isArray(resumeFrom.completed) ? resumeFrom.completed.slice() : [],
      failed: Array.isArray(resumeFrom.failed) ? resumeFrom.failed.slice() : [],
      startedAt: resumeFrom.startedAt || now,
      updatedAt: now,
      preserveSource: resumeFrom.preserveSource !== false,
    } : {
      phase: 'prep',
      chatId,
      total: 0,
      completed: [],
      failed: [],
      startedAt: now,
      updatedAt: now,
      preserveSource: true,
    };
  }

  // fire-and-forget. 단일 인스턴스 가드.
  startInBackground() {
    if (this._running) return this._promise;
    this._running = true;
    this._promise = this._run().catch(err => {
      console.error('[sns_nai] SRMigrator failed:', err && err.message ? err.message : err);
      this._notify({ phase: 'error', error: err && err.message ? err.message : String(err) });
    }).finally(() => {
      this._running = false;
    });
    return this._promise;
  }

  cancel() {
    this.cancelled = true;
  }

  _notify(extra) {
    try {
      this.onProgress(Object.assign({
        phase: this.state.phase,
        chatId: this.chatId,
        total: this.state.total,
        completedCount: this.state.completed.length,
        failedCount: this.state.failed.length,
      }, extra || {}));
    } catch (_) { /* progress callback errors must not break migration */ }
  }

  async _persistState() {
    this.state.updatedAt = Date.now();
    // dst(=PSB)에 상태 저장. SS write 0회 보장.
    try {
      await this.dst.persistKeys({ [SRMIG_STATE_KEY]: this.state });
    } catch (e) {
      console.warn('[sns_nai] SRMigrator._persistState: failed to persist state:', e.message);
    }
  }

  _checkCancelled() {
    if (this.cancelled) {
      this.state.phase = 'cancelled';
      this._notify({ phase: 'cancelled' });
      const err = new Error('SRMigrator: cancelled');
      err.cancelled = true;
      throw err;
    }
  }

  // Skip 키 판정: WHITELIST는 SS에 영구 잔존, srmig:* 는 PSB 자체 메타.
  _shouldSkip(key) {
    return key === SS_WHITELIST_KEY || key.startsWith('srmig:');
  }

  async _run() {
    // Phase 0: prep — readonly 잠금 (이미 caller가 잠갔을 수 있음, idempotent)
    this.state.phase = 'prep';
    this.store._readonly = true;
    this._notify({ phase: 'prep' });
    await this._persistState();
    this._checkCancelled();

    // Phase 1: enumerate — src 키 목록 (read only, SS write 0)
    this.state.phase = 'enumerate';
    this._notify({ phase: 'enumerate' });
    const srcKeys = await this.src.listKeys();
    const targetKeys = srcKeys.filter(k => !this._shouldSkip(k));
    // 이미 completed된 키는 제외 (재개 시).
    const completedSet = new Set(this.state.completed);
    const pendingKeys = targetKeys.filter(k => !completedSet.has(k));
    this.state.total = targetKeys.length;
    await this._persistState();
    this._checkCancelled();

    // Phase 2: mirror — _cache 값을 dst에 청크 단위 write.
    // _cache가 truth (이미 src에서 init됨). src를 다시 읽지 않음 — _cache 갱신과의 race 회피.
    this.state.phase = 'mirror';
    this._notify({ phase: 'mirror' });
    for (let i = 0; i < pendingKeys.length; i += SRMIG_CHUNK_SIZE) {
      this._checkCancelled();
      const chunk = pendingKeys.slice(i, i + SRMIG_CHUNK_SIZE);
      const map = {};
      for (const key of chunk) {
        // _cache에서 직접 읽기 (caller 보장: SRStore.init() 후 호출).
        const val = this.store._cache[key];
        if (val === undefined) continue; // 이미 삭제된 키 skip
        map[key] = val;
      }
      try {
        if (Object.keys(map).length > 0) {
          await this.dst.persistKeys(map);
        }
        for (const key of chunk) {
          if (!completedSet.has(key)) {
            this.state.completed.push(key);
            completedSet.add(key);
          }
        }
      } catch (e) {
        // 청크 전체 실패 — 키별 failed 기록 후 다음 청크 계속.
        for (const key of chunk) {
          this.state.failed.push({ key, error: e.message, phase: 'mirror' });
        }
        console.warn(`[sns_nai] SRMigrator.mirror: chunk failed: ${e.message}`);
      }
      await this._persistState();
      this._notify({ phase: 'mirror', chunkIndex: Math.floor(i / SRMIG_CHUNK_SIZE) });
    }
    this._checkCancelled();

    // Phase 3: verify — dst read-back vs _cache JSON 비교. mismatch는 failed 기록만.
    this.state.phase = 'verify';
    this._notify({ phase: 'verify' });
    try {
      const dstSnapshot = await this.dst.init();
      const failedSet = new Set(this.state.failed.map(f => f.key));
      for (const key of this.state.completed) {
        if (failedSet.has(key)) continue;
        const srcVal = this.store._cache[key];
        const dstVal = dstSnapshot[key];
        if (srcVal === undefined) continue;
        try {
          const a = JSON.stringify(srcVal);
          const b = JSON.stringify(dstVal);
          if (a !== b) {
            this.state.failed.push({ key, error: 'verify mismatch', phase: 'verify' });
          }
        } catch (e) {
          this.state.failed.push({ key, error: `verify exception: ${e.message}`, phase: 'verify' });
        }
      }
    } catch (e) {
      console.warn(`[sns_nai] SRMigrator.verify: dst.init failed: ${e.message}`);
      // verify 실패 자체는 rollback 사유 아님. 진행.
    }
    await this._persistState();
    this._checkCancelled();

    // Phase 4: flag — done flag를 dst(PSB)에 박음. SS 미터치.
    this.state.phase = 'flag';
    this._notify({ phase: 'flag' });
    await this.dst.persistKeys({
      [SRMIG_DONE_KEY]: {
        chatId: this.chatId,
        at: Date.now(),
        bytesMigrated: this._estimateBytes(),
      },
    });
    await this._persistState();
    this._checkCancelled();

    // Phase 5: swap — _cache vs dst 차이 final mirror → store._swapBackend(dst).
    this.state.phase = 'swap';
    this._notify({ phase: 'swap' });
    try {
      const dstKeys = new Set(await this.dst.listKeys());
      const finalMap = {};
      for (const key of Object.keys(this.store._cache)) {
        if (this._shouldSkip(key)) continue;
        if (!dstKeys.has(key)) {
          finalMap[key] = this.store._cache[key];
        }
      }
      if (Object.keys(finalMap).length > 0) {
        await this.dst.persistKeys(finalMap);
      }
    } catch (e) {
      console.warn(`[sns_nai] SRMigrator.swap: final mirror failed: ${e.message}`);
      // 그래도 swap 진행 — done flag 있으므로 다음 부팅이 B2 직행.
    }

    // 실제 백엔드 교체. _swapBackend가 _readonly=false + _setQueue 비우기 처리.
    await this.store._swapBackend(this.dst);

    // Phase 6: done — unlock 명시. srmig:state는 PSB에 잔존 (B2 부팅 시 state 정리 단계에서 제거).
    this.store._readonly = false;
    this.state.phase = 'done';
    await this._persistState();
    this._notify({ phase: 'done' });
  }

  _estimateBytes() {
    let total = 0;
    for (const key of this.state.completed) {
      const val = this.store._cache[key];
      if (val === undefined) continue;
      try {
        total += JSON.stringify(val).length;
      } catch (_) { /* skip */ }
    }
    return total;
  }
}

// ----------------------------------------------------------------------------
//  cleanupSourceBackend — 7일 grace 만료 시 SS의 비-WHITELIST SR 키 일괄 삭제
// ----------------------------------------------------------------------------
// 호출자: 부팅 시 grace 만료 체크 hook.
// 이 호출은 SS write 1회 발생 (cleanup 자체). 7일 후 1회 한정.
// sr:chatId:v1는 영구 잔존 (chicken-and-egg anchor).
// ----------------------------------------------------------------------------
async function cleanupSourceBackend(srcBackend, _chatId) {
  if (!srcBackend) throw new Error('cleanupSourceBackend: srcBackend required');
  // readonly 모드면 임시 해제 후 복원 (정당한 1회 cleanup).
  const wasReadonly = !!srcBackend._readonly;
  if (wasReadonly) srcBackend._readonly = false;
  try {
    const keys = await srcBackend.listKeys();
    const targets = keys.filter(k => k !== SS_WHITELIST_KEY && !k.startsWith('srmig:'));
    if (targets.length === 0) return { removed: 0 };
    const map = {};
    for (const k of targets) map[k] = undefined;
    await srcBackend.persistKeys(map);
    return { removed: targets.length };
  } finally {
    if (wasReadonly) srcBackend._readonly = true;
  }
}

// ============================================================================
//  RoomManager — DM Room CRUD
// ============================================================================

class RoomManager {
  constructor(store) {
    this.store = store;
    this.sessionTimeProvider = null;
    this.rpMomentProvider = null;
  }

  _genId() {
    return Date.now().toString(36) + Math.random().toString(36).slice(2, 6);
  }

  setSessionTimeProvider(provider) {
    this.sessionTimeProvider = typeof provider === 'function' ? provider : null;
  }

  _sessionTimeSnapshot() {
    try {
      const value = this.sessionTimeProvider?.();
      const text = value == null ? '' : String(value).trim();
      return text || null;
    } catch {
      return null;
    }
  }

  setRpMomentProvider(provider) {
    this.rpMomentProvider = typeof provider === 'function' ? provider : null;
  }

  // Sync snapshot of the current RP moment ({...,turn,source}) for storage-layer auto-stamping.
  // Priority: explicit opts.rpCreated (incl. null for inheritance) > backfill skip > provider (exception-isolated).
  _rpMomentSnapshot(opts = {}) {
    if (Object.prototype.hasOwnProperty.call(opts, 'rpCreated')) return opts.rpCreated;
    if (opts.source === 'backfill') return null;
    try { return this.rpMomentProvider?.() ?? null; } catch { return null; }
  }

  listRooms() {
    const idx = this.store.get('rooms:index');
    return idx ? idx.list : [];
  }

  getRoom(id) {
    const room = this.store.get(`room:${id}`);
    if (!room) return null;

    let changed = false;
    if (!Array.isArray(room.disabledLorebooks)) {
      room.disabledLorebooks = [];
      changed = true;
    }
    if (changed) this.store.set(`room:${id}`, room);
    return room;
  }

  peekRoom(id) {
    const room = this.store.get(`room:${id}`);
    if (!room) return null;
    return {
      ...room,
      participants: Array.isArray(room.participants) ? [...room.participants] : [],
      disabledLorebooks: Array.isArray(room.disabledLorebooks) ? [...room.disabledLorebooks] : [],
    };
  }

  async saveRoom(room, opts = {}) {
    if (!room?.id) return null;
    return this.store.set(`room:${room.id}`, room, opts.critical === false ? undefined : { critical: true });
  }

  async createRoom({ mode = 'user_dm', title, participants, userParticipantId }) {
    const id = this._genId();
    const room = {
      id, mode, title,
      participants: participants || [],
      userParticipantId: userParticipantId || null,
      unread: 0,
      msgCount: 0,
      nextSeq: 0,
      lastTs: null,
      disabledLorebooks: [],
    };

    this.store.set(`room:${id}`, room);

    const idx = this.store.get('rooms:index') || { list: [] };
    idx.list.push({ id, title, mode, lastTs: null });
    await this.store.set('rooms:index', idx, { critical: true });

    return room;
  }

  async addMessage(roomId, { sender, body, userWritten = false, media = null, hidden = null, visible = true }) {
    const room = this.store.get(`room:${roomId}`);
    if (!room) return null;

    const seq = room.nextSeq;
    const now = Date.now();
    const createdRpTime = this._sessionTimeSnapshot();
    const rpCreated = this._rpMomentSnapshot();
    const msg = {
      id: this._genId(),
      roomId,
      seq,
      sender,
      body,
      userWritten,
      state: 'delivered',
      // date-turn(오프라인 데이트 발화)도 Canon이다 — 일반 메시지와 동일하게 visible:true로 저장한다.
      // 메인 카톡 채팅 스트림에서 말풍선을 숨기는 건 visible 플래그가 아니라 렌더 단계의 media.type 스킵
      // (dm-ui _appendKakaoBubble)으로 처리한다. 그래야 date-turn이 LLM 컨텍스트엔 포함되면서도
      // 메인 채팅엔 date 카드 하나만 뜬다.
      visible: visible !== false,
      delayMs: null,
      interruptedBy: null,
      media: media || null,
      hidden: hidden || null,
      sourceTurnHash: null,
      ts: { seq, createdAt: now, extracted: null },
    };
    if (createdRpTime) msg.ts.createdRpTime = createdRpTime;
    if (rpCreated) msg.ts.rpCreated = rpCreated;

    const chunkIdx = Math.floor(seq / 50);
    const chunkKey = `room:${roomId}:msg:${chunkIdx}`;
    const chunk = this.store.get(chunkKey) || [];
    chunk.push(msg);
    this.store.set(chunkKey, chunk);

    room.nextSeq = seq + 1;
    room.msgCount = seq + 1;
    room.lastTs = msg.ts.createdAt;
    // date-turn은 visible:true(Canon)지만 메인 카톡 스트림엔 말풍선이 아니라 date 카드 하나로만 뜬다
    // (렌더 단계 media.type 스킵). 턴마다 unread를 올리면 사용자가 본 적 없는 유령 미읽음이 쌓이므로,
    // 메인 unread 카운트에서는 date-turn을 제외한다(데이트 진입은 카드 클릭→풀스크린 경로가 따로 있다).
    if (!userWritten && media?.type !== 'date-turn') room.unread++;
    this.store.set(`room:${roomId}`, room);

    const idx = this.store.get('rooms:index') || { list: [] };
    const entry = idx.list.find(r => r.id === roomId);
    if (entry) entry.lastTs = msg.ts.createdAt;
    await this.store.set('rooms:index', idx, { critical: true });

    return msg;
  }

  getLatestMessages(roomId, n = 50) {
    const room = this.store.get(`room:${roomId}`);
    if (!room || room.msgCount === 0) return [];

    let result = [];
    let chunkIdx = Math.floor((room.msgCount - 1) / 50);

    while (result.length < n && chunkIdx >= 0) {
      const chunk = this.store.get(`room:${roomId}:msg:${chunkIdx}`) || [];
      const visible = chunk.filter(m => m.visible);
      result = [...visible, ...result];
      chunkIdx--;
    }

    return result.slice(-n);
  }

  getLatestContextMessages(roomId, n = 50) {
    const room = this.store.get(`room:${roomId}`);
    if (!room || room.msgCount === 0) return [];

    let result = [];
    let chunkIdx = Math.floor((room.msgCount - 1) / 50);

    while (result.length < n && chunkIdx >= 0) {
      const chunk = this.store.get(`room:${roomId}:msg:${chunkIdx}`) || [];
      const visible = chunk.filter(m => m?.visible !== false);
      result = [...visible, ...result];
      chunkIdx--;
    }

    return result.slice(-n);
  }

  // Iterate every stored chunk in order and return all visible messages (seq-ascending).
  // For media/link collection drawers — walks the same `room:${roomId}:msg:${chunkIdx}` chunks
  // that addMessage writes, without introducing a new storage schema.
  getAllMessages(roomId, { includeHidden = false } = {}) {
    const room = this.store.get(`room:${roomId}`);
    if (!room || room.msgCount === 0) return [];

    const totalChunks = Math.floor((room.msgCount - 1) / 50) + 1;
    const result = [];
    for (let chunkIdx = 0; chunkIdx < totalChunks; chunkIdx++) {
      const chunk = this.store.get(`room:${roomId}:msg:${chunkIdx}`);
      if (!chunk) continue;
      for (const m of chunk) {
        if (!includeHidden && m?.visible === false) continue;
        result.push(m);
      }
    }
    return result;
  }

  // Convenience wrapper for the chat drawer: all messages whose media matches predicate.
  // 기본은 visible만(드로어용). includeHidden:true면 삭제(visible:false)된 메시지까지 수집한다
  // — 데이트 풀스크린 본문은 전체 턴을 빠짐없이 표시하므로 그 경로에서 true를 넘긴다(date-turn 자체는
  //   이제 visible:true Canon이라 기본 수집에도 잡힌다).
  getAllMediaMessages(roomId, predicate, { includeHidden = false } = {}) {
    const test = typeof predicate === 'function' ? predicate : (m => !!m?.media);
    return this.getAllMessages(roomId, { includeHidden }).filter(m => m?.media && test(m));
  }

  // --- Date mode (메신저 서브 채팅: 오프라인 만남 RP) ---
  // 하이브리드 저장: room.dates[]가 세션 메타(시간/장소/분위기/요약/턴수)를 들고,
  // 턴 메시지는 media='date-turn'(visible:true Canon)으로 메인 청크에 함께 저장된다 — 데이트는
  // Canon이라 LLM 컨텍스트엔 포함되고, 메인 카톡 스트림의 말풍선 숨김은 dm-ui 렌더 단계 media.type 스킵으로 처리한다.
  // room.dates는 room 객체에 중첩되므로 saveRoom의 store.set 한 번으로 통째 직렬화/보존된다.

  // 새 데이트 세션을 만들어 room.dates에 push하고 저장. 생성된 세션 객체를 반환.
  async addDate(roomId, { time = '', location = '', mood = '' } = {}) {
    const room = this.store.get(`room:${roomId}`);
    if (!room) return null;
    if (!Array.isArray(room.dates)) room.dates = [];

    const session = {
      id: this._genId(),
      createdAt: Date.now(),
      status: 'active',
      time: String(time || ''),
      location: String(location || ''),
      mood: String(mood || ''),
      summary: '',
      turnCount: 0,
    };
    room.dates.push(session);
    await this.saveRoom(room);
    return session;
  }

  getDate(roomId, dateId) {
    const room = this.store.get(`room:${roomId}`);
    if (!room || !Array.isArray(room.dates)) return null;
    return room.dates.find(d => d?.id === dateId) || null;
  }

  // 데이트 상태 전이('active'↔'done'). fresh getRoom→해당 date만 수정→saveRoom으로
  // write-race/lost-update 방지(드로어·풀스크린이 stale room을 들고 있어도 다른 필드 롤백 없음).
  async setDateStatus(roomId, dateId, status) {
    const room = this.store.get(`room:${roomId}`);
    if (!room || !Array.isArray(room.dates)) return null;
    const session = room.dates.find(d => d?.id === dateId);
    if (!session) return null;
    session.status = String(status || 'active');
    await this.saveRoom(room);
    return session;
  }

  // 데이트 메타 단일 필드 갱신(summary/time/location/mood/turnCount 등). setDateStatus와 같은 fresh 패턴.
  async updateDateField(roomId, dateId, field, value) {
    if (!field) return null;
    const room = this.store.get(`room:${roomId}`);
    if (!room || !Array.isArray(room.dates)) return null;
    const session = room.dates.find(d => d?.id === dateId);
    if (!session) return null;
    session[field] = value;
    await this.saveRoom(room);
    return session;
  }

  listDates(roomId) {
    const room = this.store.get(`room:${roomId}`);
    if (!room || !Array.isArray(room.dates)) return [];
    return room.dates.slice();
  }

  markRead(roomId) {
    this.store.update(`room:${roomId}`, room => {
      if (!room) return undefined;
      room.unread = 0;
      return room;
    });
  }

  deleteMessage(roomId, seq) {
    const { chunk, chunkKey, idx } = this._findMsgInChunk(roomId, seq);
    if (!chunk || idx < 0) return false;

    const msg = chunk[idx];
    if (!msg.visible && msg.state === 'deleted') return false;

    const wasVisibleUnread = msg.visible && !msg.userWritten;
    msg.visible = false;
    msg.state = 'deleted';
    this.store.set(chunkKey, chunk);

    const room = this.store.get(`room:${roomId}`);
    if (room) {
      if (wasVisibleUnread && room.unread > 0) {
        room.unread = Math.max(0, room.unread - 1);
      }
      const latest = this.getLatestMessages(roomId, 1).slice(-1)[0];
      room.lastTs = latest?.ts?.createdAt || null;
      this.store.set(`room:${roomId}`, room);

      const index = this.store.get('rooms:index') || { list: [] };
      const entry = index.list.find(r => r.id === roomId);
      if (entry) entry.lastTs = room.lastTs;
      this.store.set('rooms:index', index);
    }

    return true;
  }

  async deleteRoom(roomId) {
    const room = this.store.get(`room:${roomId}`);
    if (!room) return;

    const totalChunks = Math.floor((room.msgCount - 1) / 50) + 1;
    for (let i = 0; i < totalChunks; i++) {
      this.store.delete(`room:${roomId}:msg:${i}`);
    }
    this.store.delete(`room:${roomId}`);

    const idx = this.store.get('rooms:index') || { list: [] };
    idx.list = idx.list.filter(r => r.id !== roomId);
    await this.store.set('rooms:index', idx, { critical: true });
  }

  // --- Phase 2: Queue/Interrupt support ---

  async addQueuedMessage(roomId, { sender, body, delayMs = 0, media = null, hidden = null }) {
    const room = this.store.get(`room:${roomId}`);
    if (!room) return null;

    const seq = room.nextSeq;
    const now = Date.now();
    const createdRpTime = this._sessionTimeSnapshot();
    const rpCreated = this._rpMomentSnapshot();
    const msg = {
      id: this._genId(),
      roomId, seq, sender, body,
      userWritten: false,
      state: 'queued',
      visible: false,
      delayMs,
      interruptedBy: null,
      media: media || null,
      hidden: hidden || null,
      sourceTurnHash: null,
      ts: { seq, createdAt: now, extracted: null },
    };
    if (createdRpTime) msg.ts.createdRpTime = createdRpTime;
    if (rpCreated) msg.ts.rpCreated = rpCreated;

    const chunkIdx = Math.floor(seq / 50);
    const chunkKey = `room:${roomId}:msg:${chunkIdx}`;
    const chunk = this.store.get(chunkKey) || [];
    chunk.push(msg);
    this.store.set(chunkKey, chunk);

    room.nextSeq = seq + 1;
    room.msgCount = seq + 1;
    this.store.set(`room:${roomId}`, room);

    return msg;
  }

  async flushQueuedBatch() {
    await this.store.flush();
  }

  _findMsgInChunk(roomId, seq) {
    const chunkIdx = Math.floor(seq / 50);
    const chunkKey = `room:${roomId}:msg:${chunkIdx}`;
    const chunk = this.store.get(chunkKey);
    if (!chunk) return { chunk: null, chunkKey, idx: -1 };
    const idx = chunk.findIndex(m => m.seq === seq);
    return { chunk, chunkKey, idx };
  }

  deliverMessage(roomId, msg) {
    const { chunk, chunkKey, idx } = this._findMsgInChunk(roomId, msg.seq);
    if (!chunk || idx < 0) return null;
    if (chunk[idx].state !== 'queued') return null;

    const deliveredAt = Date.now();
    const deliveredRpTime = this._sessionTimeSnapshot();
    chunk[idx].state = 'delivered';
    chunk[idx].visible = true;
    chunk[idx].ts = { ...(chunk[idx].ts || {}), deliveredAt };
    if (deliveredRpTime) chunk[idx].ts.deliveredRpTime = deliveredRpTime;
    this.store.set(chunkKey, chunk);

    const room = this.store.get(`room:${roomId}`);
    if (room) {
      room.unread++;
      room.lastTs = chunk[idx].ts.deliveredAt;
      this.store.set(`room:${roomId}`, room);

      const index = this.store.get('rooms:index') || { list: [] };
      const entry = index.list.find(r => r.id === roomId);
      if (entry) entry.lastTs = room.lastTs;
      this.store.set('rooms:index', index);
    }

    return chunk[idx];
  }

  interruptMessage(roomId, msg, interruptedBy) {
    const { chunk, chunkKey, idx } = this._findMsgInChunk(roomId, msg.seq);
    if (!chunk || idx < 0) return false;
    if (chunk[idx].state !== 'queued') return false;

    chunk[idx].state = 'interrupted';
    chunk[idx].visible = false;
    chunk[idx].interruptedBy = interruptedBy;
    this.store.set(chunkKey, chunk);
    return true;
  }

  updateMessageMedia(roomId, seq, media, opts = {}) {
    const { chunk, chunkKey, idx } = this._findMsgInChunk(roomId, seq);
    if (!chunk || idx < 0) return null;

    chunk[idx].media = media || null;
    this.store.set(chunkKey, chunk, opts.critical ? { critical: true } : undefined);
    return chunk[idx];
  }

  async updateMessageMediaCritical(roomId, seq, media) {
    const { chunk, chunkKey, idx } = this._findMsgInChunk(roomId, seq);
    if (!chunk || idx < 0) return null;

    chunk[idx].media = media || null;
    await this.store.set(chunkKey, chunk, { critical: true });
    return chunk[idx];
  }

  getInterruptedMessages(roomId, limit = 5) {
    const room = this.store.get(`room:${roomId}`);
    if (!room || room.msgCount === 0) return [];

    const result = [];
    let chunkIdx = Math.floor((room.msgCount - 1) / 50);

    while (result.length < limit && chunkIdx >= 0) {
      const chunk = this.store.get(`room:${roomId}:msg:${chunkIdx}`) || [];
      for (let i = chunk.length - 1; i >= 0 && result.length < limit; i--) {
        if (chunk[i].state === 'interrupted') result.unshift(chunk[i]);
      }
      chunkIdx--;
    }
    return result;
  }

  cleanupStaleQueued() {
    const rooms = this.listRooms();
    for (const r of rooms) {
      const room = this.store.get(`room:${r.id}`);
      if (!room) continue;
      const totalChunks = Math.ceil(room.msgCount / 50);
      for (let c = 0; c < totalChunks; c++) {
        const chunkKey = `room:${r.id}:msg:${c}`;
        const chunk = this.store.get(chunkKey);
        if (!chunk) continue;
        let changed = false;
        for (const msg of chunk) {
          if (msg.state === 'queued') {
            msg.state = 'interrupted';
            msg.visible = false;
            msg.interruptedBy = { actorId: 'system', reason: 'stale_reload' };
            changed = true;
          }
        }
        if (changed) this.store.set(chunkKey, chunk);
      }
    }
  }
}

// ============================================================================
//  MessageQueue — Delayed Delivery + Interrupt
// ============================================================================

class MessageQueue {
  constructor(roomManager) {
    this.rm = roomManager;
    this.onDelivered = null;
    this.onQueueDone = null;
    this._queues = {};
  }

  async _queueMessages(roomId, messages) {
    await this.cancelAndInterrupt(roomId, 'system', 'new_enqueue');

    const queuedMsgs = [];
    for (const m of messages) {
      const msg = await this.rm.addQueuedMessage(roomId, {
        sender: m.sender,
        body: m.body,
        delayMs: m.delayMs || 0,
        media: m.media || null,
        hidden: m.hidden || null,
      });
      if (msg) queuedMsgs.push(msg);
    }
    await this.rm.flushQueuedBatch();
    return queuedMsgs;
  }

  _startDelivery(roomId, queuedMsgs) {
    return new Promise((resolve) => {
      this._queues[roomId] = {
        messages: queuedMsgs,
        currentIdx: 0,
        timer: null,
        cancelled: false,
        resolve,
      };
      this._deliverNext(roomId);
    });
  }

  async enqueue(roomId, messages) {
    const queuedMsgs = await this._queueMessages(roomId, messages);
    if (queuedMsgs.length === 0) return 'completed';
    return this._startDelivery(roomId, queuedMsgs);
  }

  async enqueueDetached(roomId, messages) {
    const queuedMsgs = await this._queueMessages(roomId, messages);
    if (queuedMsgs.length === 0) return { status: 'completed', messages: [], deliveryPromise: Promise.resolve('completed') };
    const deliveryPromise = this._startDelivery(roomId, queuedMsgs);
    deliveryPromise.catch(e => console.error('[sns_nai] Detached queue error:', e.message));
    return { status: 'queued', messages: queuedMsgs, deliveryPromise };
  }

  _deliverNext(roomId) {
    const q = this._queues[roomId];
    if (!q || q.cancelled || q.currentIdx >= q.messages.length) {
      const resolve = q?.resolve;
      delete this._queues[roomId];
      if (this.onQueueDone) this.onQueueDone(roomId);
      if (resolve) resolve(q.cancelled ? 'interrupted' : 'completed');
      return;
    }

    const msg = q.messages[q.currentIdx];
    const delay = q.currentIdx === 0 ? 0 : (msg.delayMs || 0);

    q.timer = setTimeout(async () => {
      q.timer = null;
      if (q.cancelled) return;

      try {
        const delivered = this.rm.deliverMessage(roomId, msg);
        q.currentIdx++;
        if (delivered && this.onDelivered) {
          this.onDelivered(roomId, delivered);
        }
        await this.rm.store.flush();
      } catch (e) {
        console.error('[sns_nai] Queue deliver error:', e.message);
        q.currentIdx++;
      }
      this._deliverNext(roomId);
    }, delay);
  }

  async interrupt(roomId, actorId, reason = 'user_input') {
    const q = this._queues[roomId];
    if (!q || q.cancelled) return [];

    q.cancelled = true;
    if (q.timer) {
      clearTimeout(q.timer);
      q.timer = null;
    }

    const interrupted = [];
    for (let i = q.currentIdx; i < q.messages.length; i++) {
      const ok = this.rm.interruptMessage(roomId, q.messages[i], {
        actorId, reason,
      });
      if (ok) interrupted.push(q.messages[i]);
    }

    const resolve = q.resolve;
    delete this._queues[roomId];
    if (resolve) resolve('interrupted');
    return interrupted;
  }

  async cancelAndInterrupt(roomId, actorId = 'system', reason = 'cancel') {
    await this.interrupt(roomId, actorId, reason);
  }

  hasActiveQueue(roomId) {
    const q = this._queues[roomId];
    return q && !q.cancelled;
  }

  getTypingSender(roomId) {
    const q = this._queues[roomId];
    if (!q || q.cancelled || q.currentIdx >= q.messages.length) return null;
    return q.messages[q.currentIdx].sender;
  }
}

// ============================================================================
//  ProgressManager — Global bottom status bar for long-running tasks
// ============================================================================

class ProgressManager {
  constructor() {
    this.el = null;
    this.tasks = [];
    this._seq = 0;
  }

  createTaskId(prefix = 'task') {
    this._seq += 1;
    return `${prefix}_${Date.now()}_${this._seq}`;
  }

  createDOM() {
    const root = document.createElement('div');
    root.className = 'sr-status-bar';
    root.setAttribute('role', 'status');
    root.setAttribute('aria-live', 'polite');

    const bar = document.createElement('div');
    bar.className = 'sr-progress-bar';

    const fill = document.createElement('div');
    fill.className = 'sr-progress-fill';
    bar.appendChild(fill);

    const text = document.createElement('div');
    text.className = 'sr-status-text';

    root.appendChild(bar);
    root.appendChild(text);

    this.el = { root, bar, fill, text };
    this._render();
    return root;
  }

  startTask(id, label, total = 0) {
    const taskId = id || this.createTaskId();
    const task = {
      id: taskId,
      label: label || '작업 진행 중...',
      current: 0,
      total: this._safeNumber(total),
      startedAt: Date.now(),
      updatedAt: Date.now(),
    };
    this.tasks = this.tasks.filter(t => t.id !== taskId);
    this.tasks.push(task);
    this._render();

    return {
      id: taskId,
      update: patch => this.updateTask(taskId, patch),
      complete: () => this.completeTask(taskId),
    };
  }

  updateTask(id, { current, total, label } = {}) {
    const task = this.tasks.find(t => t.id === id);
    if (!task) return;
    if (label !== undefined) task.label = label || '작업 진행 중...';
    if (total !== undefined) task.total = this._safeNumber(total);
    if (current !== undefined) task.current = this._safeNumber(current);
    if (task.total > 0) task.current = Math.max(0, Math.min(task.current, task.total));
    task.updatedAt = Date.now();
    this._render();
  }

  completeTask(id) {
    this.tasks = this.tasks.filter(t => t.id !== id);
    this._render();
  }

  clear() {
    this.tasks = [];
    this._render();
  }

  _safeNumber(value) {
    const num = Number(value);
    return Number.isFinite(num) ? num : 0;
  }

  _activeTask() {
    return this.tasks.slice().sort((a, b) => b.updatedAt - a.updatedAt)[0] || null;
  }

  _formatTask(task) {
    const label = task.label || '작업 진행 중...';
    if (task.total > 0) {
      return `${label} (${Math.round(task.current)}/${Math.round(task.total)})`;
    }
    return label;
  }

  _render() {
    if (!this.el) return;
    const active = this._activeTask();
    if (!active) {
      this.el.root.classList.remove('is-visible');
      this.el.fill.classList.remove('is-indeterminate');
      this.el.fill.style.width = '0%';
      this.el.text.textContent = '';
      return;
    }

    const hasTotal = active.total > 0;
    const pct = hasTotal ? Math.max(0, Math.min(100, (active.current / active.total) * 100)) : 35;
    const prefix = this.tasks.length > 1 ? `${this.tasks.length}개 작업 진행 중... ` : '';

    this.el.root.classList.add('is-visible');
    this.el.fill.classList.toggle('is-indeterminate', !hasTotal);
    this.el.fill.style.width = `${pct}%`;
    this.el.text.textContent = prefix + this._formatTask(active);
  }
}

