class PromptBuilder {
  constructor(store) {
    this.store = store;
    this.blocks = { ...DEFAULT_BLOCKS, ...XDM_BLOCKS };
    this.messageBlocks = { ...DEFAULT_MESSAGE_BLOCKS };
    this.globalOverrides = {};
    this.chatOverrides = {};
  }

  async loadOverrides() { /* Phase E */ }

  _resolve(key) {
    return this.chatOverrides[key] ?? this.globalOverrides[key] ?? this.blocks[key] ?? null;
  }

  _resolveMessages(key) {
    return this.chatOverrides[key] ?? this.globalOverrides[key] ?? this.messageBlocks[key] ?? null;
  }

  getBlock(key, vars = {}) {
    const raw = this._resolve(key);
    if (raw == null) {
      console.warn(`[PromptBuilder] missing block: ${key}`);
      return '';
    }
    return this._interpolate(raw, vars);
  }

  tryGetBlock(key, vars = {}) {
    const raw = this._resolve(key);
    return raw != null ? this._interpolate(raw, vars) : null;
  }

  getMessages(key, vars = {}) {
    const raw = this._resolveMessages(key);
    if (!Array.isArray(raw)) return [];
    return raw.map(m => ({ role: m.role, content: this._interpolate(m.content, vars) }));
  }

  _interpolate(text, vars) {
    return String(text || '').replace(/\{([A-Za-z][\w.-]*)\}/g, (match, key, offset, src) => {
      if (src[offset - 1] === '{' || src[offset + match.length] === '}') return match;
      return Object.prototype.hasOwnProperty.call(vars, key) ? String(vars[key]) : match;
    });
  }

  static estimateTokens(text) {
    let count = 0;
    for (const ch of String(text || '')) {
      count += (ch.codePointAt(0) > 0x2E80) ? 1.5 : 0.25;
    }
    return Math.ceil(count);
  }
}

