function isMessengerAccount(accountOrPlatform) {
  return (typeof accountOrPlatform === 'string' ? accountOrPlatform : accountOrPlatform?.platform) === 'messenger';
}

function accountPlatformLabel(platform) {
  return platform === 'twitter' ? 'X'
    : platform === 'instagram' ? 'Instagram'
    : platform === 'onlyfans' ? 'OnlyFans'
    : platform === 'messenger' ? '카카오톡'
    : (platform || '');
}

function accountDisplayLabel(acc, opts = {}) {
  if (!acc) return '';
  const parts = [];
  if (isMessengerAccount(acc)) {
    parts.push(accountPlatformLabel(acc.platform));
    parts.push(acc.displayName || '이름 없음');
    if (acc.bio) parts.push(`상태: ${acc.bio}`);
  } else {
    parts.push(acc.handle ? `@${acc.handle}` : '(handle 없음)');
    parts.push(accountPlatformLabel(acc.platform) || acc.platform);
    if (opts.includeType !== false && acc.type) parts.push(acc.type);
    if (acc.nsfwLevel != null) parts.push(`NSFW ${acc.nsfwLevel}`);
  }
  if (opts.includeStatus && acc.status) parts.push(acc.status);
  return parts.filter(Boolean).join(' · ');
}

function normalizeAccountPromptCharacter(profile = {}) {
  const imageTags = profile.imageTags || {};
  const handles = profile.handles && typeof profile.handles === 'object'
    ? Object.values(profile.handles).filter(Boolean).map(h => String(h).replace(/^@+/, ''))
    : [];
  return {
    realname: profile.realname || profile.name || profile.pkey || '',
    persona: profile.persona || '',
    bio: profile.bio || '',
    appearance: profile.appearance || '',
    baseTags: profile.baseTags || imageTags.baseTags || '',
    spoilerNotes: profile.spoilerNotes || '',
    handleSuggestions: Array.isArray(profile.handleSuggestions) ? profile.handleSuggestions : handles,
  };
}

