// ============================================================================
//  FollowGraph — per-platform follow relationships + synthetic follower counts
// ============================================================================

class FollowGraph {
  constructor(store) {
    this.store = store;
    this._data = null;
  }

  _load() {
    if (!this._data) {
      this._data = this.store.get('followgraph:v1') || {
        platforms: {
          twitter: { edges: {}, synthetic: {} },
          instagram: { edges: {}, synthetic: {} },
          onlyfans: { edges: {}, synthetic: {} },
        }
      };
    }
    return this._data;
  }

  _save() {
    if (this._data) this.store.set('followgraph:v1', this._data);
  }

  _platformData(platform) {
    const d = this._load();
    if (!d.platforms[platform]) d.platforms[platform] = { edges: {}, synthetic: {} };
    return d.platforms[platform];
  }

  follow(followerAccountId, followeeAccountId, platform, source = 'auto') {
    const pd = this._platformData(platform);
    if (!pd.edges[followerAccountId]) pd.edges[followerAccountId] = {};
    if (pd.edges[followerAccountId][followeeAccountId]) return false;
    pd.edges[followerAccountId][followeeAccountId] = { source, createdAt: Date.now() };
    this._save();
    return true;
  }

  unfollow(followerAccountId, followeeAccountId, platform) {
    const pd = this._platformData(platform);
    if (!pd.edges[followerAccountId]?.[followeeAccountId]) return false;
    delete pd.edges[followerAccountId][followeeAccountId];
    if (Object.keys(pd.edges[followerAccountId]).length === 0) delete pd.edges[followerAccountId];
    this._save();
    return true;
  }

  isFollowing(followerAccountId, followeeAccountId, platform) {
    const pd = this._platformData(platform);
    return !!pd.edges[followerAccountId]?.[followeeAccountId];
  }

  getFollowing(accountId, platform) {
    const pd = this._platformData(platform);
    return Object.keys(pd.edges[accountId] || {});
  }

  getFollowers(accountId, platform) {
    const pd = this._platformData(platform);
    const followers = [];
    for (const [fid, targets] of Object.entries(pd.edges)) {
      if (targets[accountId]) followers.push(fid);
    }
    return followers;
  }

  getFollowerCount(accountId, platform) {
    const pd = this._platformData(platform);
    const realFollowers = this.getFollowers(accountId, platform).length;
    const syn = pd.synthetic[accountId] || { baseFollowers: 0, npcDelta: 0 };
    return syn.baseFollowers + syn.npcDelta + realFollowers;
  }

  getFollowingCount(accountId, platform) {
    return this.getFollowing(accountId, platform).length;
  }

  setSynthetic(accountId, platform, baseFollowers, npcDelta = 0) {
    const pd = this._platformData(platform);
    pd.synthetic[accountId] = { baseFollowers, npcDelta, updatedAt: Date.now() };
    this._save();
  }

  adjustNpcDelta(accountId, platform, delta) {
    const pd = this._platformData(platform);
    if (!pd.synthetic[accountId]) pd.synthetic[accountId] = { baseFollowers: 0, npcDelta: 0, updatedAt: Date.now() };
    pd.synthetic[accountId].npcDelta += delta;
    pd.synthetic[accountId].updatedAt = Date.now();
    this._save();
  }

  initFromRelationships(relationships, accountRegistry, followAllowedFn = null) {
    if (!relationships || !accountRegistry) return;
    const allAccounts = accountRegistry.getAll();
    for (const rel of relationships) {
      const subjectAccounts = allAccounts.filter(a => a.profileId === rel.subject);
      const objectAccounts = allAccounts.filter(a => a.profileId === rel.object);
      for (const sa of subjectAccounts) {
        for (const oa of objectAccounts) {
          if (sa.platform !== oa.platform) continue;
          if (followAllowedFn && !followAllowedFn(sa, oa)) continue;
          const bilateral = ['friend_of', 'colleague_of', 'sibling_of', 'partner_of', 'spouse_of'].includes(rel.predicate);
          const fanDirection = rel.predicate === 'fan_of';
          if (bilateral) {
            this.follow(sa.id, oa.id, sa.platform, 'auto');
            this.follow(oa.id, sa.id, sa.platform, 'auto');
          } else if (fanDirection) {
            this.follow(sa.id, oa.id, sa.platform, 'auto');
          } else {
            this.follow(sa.id, oa.id, sa.platform, 'auto');
          }
        }
      }
    }
  }

  reset() {
    this._data = { platforms: { twitter: { edges: {}, synthetic: {} }, instagram: { edges: {}, synthetic: {} }, onlyfans: { edges: {}, synthetic: {} } } };
    this._save();
  }
}

// ============================================================================
//  Economy — virtual currency for OnlyFans simulation
// ============================================================================

class Economy {
  constructor(store) {
    this.store = store;
  }

  _load() {
    return this.store.get('economy:v1') || {
      balanceCents: 10000,
      ledger: [],
      subscriptions: {},
      purchases: {},
    };
  }

  _save(data) {
    this.store.set('economy:v1', data);
  }

  getBalance() {
    return this._load().balanceCents;
  }

  getBalanceFormatted() {
    return `$${(this.getBalance() / 100).toFixed(2)}`;
  }

  spend(amountCents, type, description, toAccountId = null, postId = null) {
    const data = this._load();
    if (data.balanceCents < amountCents) return { success: false, reason: 'insufficient_balance' };
    data.balanceCents -= amountCents;
    data.ledger.push({ id: Date.now().toString(36), ts: Date.now(), type, amountCents: -amountCents, description, toAccountId, postId });
    if (data.ledger.length > 50) data.ledger.splice(0, data.ledger.length - 50);
    this._save(data);
    return { success: true, balance: data.balanceCents };
  }

  earn(amountCents, type, description, fromAccountId = null) {
    const data = this._load();
    data.balanceCents += amountCents;
    data.ledger.push({ id: Date.now().toString(36), ts: Date.now(), type, amountCents, description, fromAccountId });
    if (data.ledger.length > 50) data.ledger.splice(0, data.ledger.length - 50);
    this._save(data);
    return { success: true, balance: data.balanceCents };
  }

  subscribe(creatorAccountId, priceCents) {
    const result = this.spend(priceCents, 'subscription', `Subscribe to creator`, creatorAccountId);
    if (!result.success) return result;
    const data = this._load();
    const now = Date.now();
    data.subscriptions[creatorAccountId] = {
      priceCents, status: 'active',
      startedAt: now, expiresAt: now + 30 * 24 * 60 * 60 * 1000,
    };
    this._save(data);
    return { success: true, balance: data.balanceCents };
  }

  isSubscribed(creatorAccountId) {
    const data = this._load();
    const sub = data.subscriptions[creatorAccountId];
    return sub?.status === 'active' && sub.expiresAt > Date.now();
  }

  purchasePPV(postId, priceCents) {
    const result = this.spend(priceCents, 'ppv', `Unlock PPV post`, null, postId);
    if (!result.success) return result;
    const data = this._load();
    data.purchases[postId] = { priceCents, purchasedAt: Date.now() };
    this._save(data);
    return { success: true, balance: data.balanceCents };
  }

  isPurchased(postId) {
    return !!this._load().purchases[postId];
  }

  tip(toAccountId, amountCents) {
    return this.spend(amountCents, 'tip', `Tip to creator`, toAccountId);
  }

  addBalance(amountCents) {
    return this.earn(amountCents, 'topup', 'Balance top-up');
  }

  getLedger() {
    return this._load().ledger.slice().reverse();
  }

  getSubscriptions() {
    return this._load().subscriptions;
  }
}

// ============================================================================
//  NotificationManager
// ============================================================================

class NotificationManager {
  constructor(store) { this.store = store; }

  getAll() { return this.store.get('notifications') || []; }

  add({ type, title, body, targetId, appId }) {
    const all = this.getAll();
    all.push({ id: Date.now().toString(36) + Math.random().toString(36).slice(2,5), type, appId: appId || null, title, body, targetId, ts: Date.now(), read: false });
    if (all.length > 50) all.splice(0, all.length - 50);
    this.store.set('notifications', all);
    if (this.onUpdate) this.onUpdate();
  }

  getUnreadCount() { return this.getAll().filter(n => !n.read).length; }

  markRead(id) {
    const all = this.getAll();
    const target = all.find(n => n.id === id);
    if (!target || target.read) return;
    target.read = true;
    this.store.set('notifications', all);
    if (this.onUpdate) this.onUpdate();
  }

  markAllRead() {
    const all = this.getAll();
    for (const n of all) n.read = true;
    this.store.set('notifications', all);
    if (this.onUpdate) this.onUpdate();
  }

  clearAll() {
    this.store.set('notifications', []);
    if (this.onUpdate) this.onUpdate();
  }
}

// ============================================================================
//  EngagementGenerator — Tier 1 algorithmic stats
// ============================================================================

class EngagementGenerator {
  generate(authorProfile, platform) {
    const pop = (authorProfile?.popularity !== null && authorProfile?.popularity !== undefined)
      ? authorProfile.popularity : 50;
    const platMult = { twitter: 1, instagram: 1.5, onlyfans: 0.3 }[platform] || 1;
    const base = pop * platMult;
    const variance = 0.7 + Math.random() * 0.6;
    let likes = Math.round(base * variance * 10);
    const flop = Math.random() < 0.1;
    if (flop) likes = Math.round(likes * 0.2);
    return { likes: Math.max(0, likes) };
  }
}

