class TemplateComments {
  constructor() {
    this.templates = {
      positive_ko: ['와 진짜 좋다', '대박 ㅋㅋ', '최고!', '이거 너무 좋아요', '진짜 부럽다', '역시!!', '대박이다 ㅋㅋ', '와...', '짱', '좋아요 ❤️'],
      positive_en: ['love this!', 'so pretty!', 'goals 😍', 'amazing!', 'omg queen 💕', 'stunning!', 'yesss!', 'iconic', 'slaying', 'beautiful ✨'],
      negative_ko: ['ㅋㅋㅋ 이게 뭐야', '별로인데..', 'ㅎ..', '글쎄', '음...'],
      negative_en: ['ratio', 'mid', 'hmm', 'nah', 'L take'],
      neutral_ko: ['오', 'ㅇㅇ', 'ㄹㅇ', '그렇구나', 'ㅋㅋ'],
      neutral_en: ['hmm', 'interesting', 'ok', 'huh', 'I see'],
      thirsty_ko: ['😍😍😍', 'ㅎㄷㄷ', '헉', '와...', '🔥🔥', '어머', '대박...'],
      thirsty_en: ['😍😍😍', '🔥🔥', '💀', 'oh my', 'excuse me??', 'I cant', 'help'],
      question_ko: ['어디야?', '이거 어디꺼?', 'TMI 좀', '뭐야 이거?'],
      question_en: ['where is this?', 'what brand?', 'details pls', 'link?'],
    };
    this.names_ko = ['팬123', '일상기록', '뉴비', '맛집탐방', '카페라떼', '아침형', '핫이슈', '운동러', '독서광', '고양이집사'];
    this.names_en = ['daily_life_', 'sky_dreamer', 'xoxo_fan', 'morning_glory', 'lol_moment', 'coffee_lover', 'sunset_chaser', 'chill_vibes', 'bookworm', 'pixel_art'];
  }

  generate(post, engagementLevel, lang = 'ko') {
    const count = engagementLevel === 'high' ? 3 + Math.floor(Math.random() * 3)
      : engagementLevel === 'medium' ? 1 + Math.floor(Math.random() * 3)
      : Math.random() < 0.5 ? 1 : 0;

    if (count === 0) return [];

    const isInsta = post.platform === 'instagram';
    const comments = [];
    const names = lang === 'en' ? this.names_en : this.names_ko;

    for (let i = 0; i < count; i++) {
      const tone = this._pickTone(isInsta);
      const pool = this.templates[`${tone}_${lang}`] || this.templates[tone] || this.templates[`${tone}_ko`] || [];
      if (pool.length === 0) continue;

      comments.push({
        id: Date.now().toString(36) + Math.random().toString(36).slice(2,5),
        postId: post.id,
        parentId: null,
        author: names[Math.floor(Math.random() * names.length)] + Math.floor(Math.random() * 999),
        body: pool[Math.floor(Math.random() * pool.length)],
        likes: Math.floor(Math.random() * 20),
        viewerLiked: false,
        source: 'template',
        ts: Date.now() - Math.floor(Math.random() * 3600000),
      });
    }
    return comments;
  }

  _pickTone(isInsta) {
    const r = Math.random();
    if (isInsta) return r < 0.5 ? 'positive' : r < 0.7 ? 'thirsty' : r < 0.85 ? 'neutral' : 'question';
    return r < 0.35 ? 'positive' : r < 0.55 ? 'neutral' : r < 0.7 ? 'negative' : r < 0.85 ? 'thirsty' : 'question';
  }
}

