// ============================================================================
//  RecurringNPCManager — Tier 3 named extras
// ============================================================================

class RecurringNPCManager {
  constructor(store, llm) {
    this.store = store;
    this.llm = llm;
    this.promptBuilder = null;
    this._busy = false;
  }

  getAll() { return this.store.get('recurring_npcs') || []; }

  async save(npcs) { await this.store.set('recurring_npcs', npcs, { critical: true }); }

  _commentRulesForPlatform(platform) {
    if (this.promptBuilder) {
      return this.promptBuilder.tryGetBlock(`agent.npc_comment_rules.${platform}`) ?? this.promptBuilder.getBlock('agent.npc_comment_rules.default');
    }
    if (platform === 'twitter') {
      return 'X/Twitter comment style: short, reactive, conversational, memey when appropriate.';
    }
    if (platform === 'instagram') {
      return 'Instagram comment style: supportive, aesthetic-focused, emoji-friendly, less confrontational.';
    }
    if (platform === 'onlyfans') {
      return 'OnlyFans comment style: subscriber voice, familiar, appreciative, intimate or tip-oriented when appropriate.';
    }
    return 'Comment style: match the platform, post language, and post mood.';
  }

  async generateComment(npc, post) {
    if (this._busy) return null;
    this._busy = true;
    try {
      const platform = post.platform || 'twitter';
      const npcSystemPrompt = this.promptBuilder
        ? this.promptBuilder.getBlock('agent.npc_comment', {
            npcName: npc.name, npcHandle: npc.handle, npcPersonality: npc.personality,
            platform, npcCommentRules: this._commentRulesForPlatform(platform),
          })
        : `You are "${npc.name}" (@${npc.handle}). ${npc.personality}. Write one short comment (1 sentence max) on a ${platform} post. Match the post language. ${this._commentRulesForPlatform(platform)}`;
      const raw = await this.llm.generate(
        npcSystemPrompt,
        `Post: "${post.body?.slice(0, 150)}"`,
        { tier: 'verylight', temperature: 0.8 }
      );
      return raw?.trim()?.slice(0, 200) || null;
    } catch (e) {
      console.error('[sns_nai] NPC comment error:', e.message);
      return null;
    } finally {
      this._busy = false;
    }
  }

  async autoGenerate() {
    const archetypes = [
      { personality: 'Loyal fan account. Always supportive and enthusiastic.', style: 'positive' },
      { personality: 'Snarky reply guy. Sarcastic but not mean.', style: 'negative' },
      { personality: 'Curious follower. Asks questions about everything.', style: 'question' },
      { personality: 'Silent observer who occasionally drops fire emojis.', style: 'thirsty' },
      { personality: 'News/gossip account. Reports on events formally.', style: 'neutral' },
    ];
    const npcs = archetypes.slice(0, 5).map((a, i) => ({
      id: Date.now().toString(36) + '_' + i,
      name: `NPC_${['Fan','Critic','Curious','Lurker','Reporter'][i]}`,
      handle: `${['loyal_fan','sharp_tongue','curious_cat','silent_watcher','daily_report'][i]}${Math.floor(Math.random()*99)}`,
      personality: a.personality,
      platform: ['twitter', 'twitter', 'instagram', 'instagram', 'twitter'][i],
      commentStyle: a.style,
      enabled: true,
    }));
    await this.save(npcs);
    return npcs;
  }
}

// ============================================================================
//  MoodSystem — Story-reactive posting moods
// ============================================================================

class MoodSystem {
  constructor(eventExtractor, profiles) {
    this.events = eventExtractor;
    this.profiles = profiles;
    this._cache = {};
    this._evFingerprint = '';
  }

  getMood(profilePkey) {
    const events = this.events?.getEvents() || [];
    const fp = events.map(e => e.id).join(',');
    if (fp !== this._evFingerprint) {
      this._cache = {};
      this._evFingerprint = fp;
    }
    if (this._cache[profilePkey]) return this._cache[profilePkey];

    const recentEvents = events.filter(e =>
      (e.participantIds?.includes(profilePkey) || e.participants?.some(p => this.profiles?.resolve(p)?.pkey === profilePkey))
      && (Date.now() - e.ts < 86400000)
    );

    if (recentEvents.length === 0) {
      this._cache[profilePkey] = null;
      return null;
    }

    const tones = recentEvents.map(e => e.emotionalTone?.toLowerCase() || '');
    const moodMap = {
      sad: { mood: 'melancholic', preferredTone: 'angsty' },
      angry: { mood: 'aggressive', preferredTone: 'vent' },
      happy: { mood: 'upbeat', preferredTone: 'wholesome' },
      anxious: { mood: 'nervous', preferredTone: 'neutral' },
      romantic: { mood: 'dreamy', preferredTone: 'flirty' },
      tense: { mood: 'edgy', preferredTone: 'vent' },
      excited: { mood: 'energetic', preferredTone: 'flex' },
    };

    for (const tone of tones) {
      for (const [key, val] of Object.entries(moodMap)) {
        if (tone.includes(key)) {
          this._cache[profilePkey] = val;
          return val;
        }
      }
    }

    this._cache[profilePkey] = null;
    return null;
  }
}

// ============================================================================
//  EventExtractor
// ============================================================================

class EventExtractor {
  constructor(store, llm, profiles) {
    this.store = store;
    this.llm = llm;
    this.profiles = profiles;
    this.promptBuilder = null;
    this.progress = null;
    this._lastMsgCount = 0;
  }

  getEvents() { return this.store.get('events') || []; }

  async extract(chatMessages) {
    if (!chatMessages || chatMessages.length < 3) return [];
    if (chatMessages.length === this._lastMsgCount) return this.getEvents();
    const progressTask = this.progress?.startTask(
      this.progress.createTaskId('event_extract'),
      '이벤트 추출 중...'
    );

    try {
    const recent = chatMessages.slice(-(this.contextConfig?.eventRp || 10));
    const text = recent.map(m => `[${m.role}] ${(m.data || '').slice(0, 300)}`).join('\n');

    const raw = await this.llm.generate(
      this.promptBuilder?.getBlock('agent.event_extract') || 'Extract 1-3 recent notable events from this roleplay. For each: summary (1 sentence), participants (character names), location, visibility (public/private/secret), emotionalTone. Output JSON array only.',
      text,
      { tier: 'light', temperature: 0.2 }
    );

    const jsonStr = new Validator()._extractJSON(raw);
    if (!jsonStr) return this.getEvents();

    try {
      const arr = JSON.parse(jsonStr);
      if (!Array.isArray(arr)) return this.getEvents();

      const events = arr.map((e, i) => ({
        id: Date.now().toString(36) + '_' + i,
        summary: String(e.summary || ''),
        participants: (e.participants || []).map(String),
        participantIds: (e.participants || []).map(name => this.profiles?.resolve(name)?.pkey || name),
        location: String(e.location || ''),
        visibility: ['public', 'private', 'secret'].includes(e.visibility) ? e.visibility : 'public',
        emotionalTone: String(e.emotionalTone || ''),
        ts: Date.now(),
      })).filter(e => e.summary);

      const existing = this.getEvents();
      const merged = [...existing, ...events].slice(-20);
      this.store.set('events', merged);
      this._lastMsgCount = chatMessages.length;
      return merged;
    } catch { return this.getEvents(); }
    } finally {
      progressTask?.complete();
    }
  }

  getEventById(id) {
    return this.getEvents().find(e => e.id === id) || null;
  }

  async deleteEvent(id) {
    const events = this.getEvents().filter(e => e.id !== id);
    await this.store.set('events', events, { critical: true });
    return events;
  }

  checkVisibility(event, authorId) {
    if (!event) return { allowed: true, mode: 'full' };
    if (event.visibility === 'public') return { allowed: true, mode: 'full' };
    if (event.visibility === 'private') {
      const isParticipant = event.participantIds?.includes(authorId) || event.participants?.includes(authorId);
      return isParticipant ? { allowed: true, mode: 'full' } : { allowed: false, mode: 'none' };
    }
    if (event.visibility === 'secret') {
      const isParticipant = event.participantIds?.includes(authorId) || event.participants?.includes(authorId);
      return isParticipant ? { allowed: true, mode: 'vague' } : { allowed: false, mode: 'none' };
    }
    return { allowed: true, mode: 'full' };
  }
}

// ============================================================================
//  TimeTracker
// ============================================================================

// Conservative static ReDoS guard. Parses the pattern with a paren stack and rejects the classes
// that cause catastrophic backtracking: nested unbounded quantifiers (star height >= 2, including
// through groups like ((?:a+))+ ), unbounded-quantified groups containing top-level alternation
// ( (a|aa)* ), adjacent identical unbounded atoms ( \d+\d+ ), excessive nesting/quantifier count.
// Tuned to PASS the simple time/place notations this plugin uses while blocking known ReDoS forms.
// Static detection is undecidable in general, so this pairs with the length cap (<=200) + try/catch
// + the runtime input slice caps in extractTime/_extractLocation. Verified: 0 false-positives on the
// default/expected patterns, 0 bypasses on a catastrophic-pattern test set.
function isLinearTimeRegex(src) {
  const s = String(src);
  const n = s.length;
  const stack = [{ alt: false, innerHeight: 0, hasVar: false }];
  let unboundedCount = 0;
  let prevAtom = null;
  let i = 0;
  // kind: none|bounded|unbounded; variable=true for any non-fixed repeat (*, +, ?, {n,}, {m,n} m!=n).
  const readQuant = (j) => {
    if (j >= n) return { kind: 'none', variable: false, end: j };
    const c = s[j];
    if (c === '*' || c === '+') {
      let end = j + 1;
      if (s[end] === '?' || s[end] === '+') end++;
      return { kind: 'unbounded', variable: true, end };
    }
    if (c === '?') {
      let end = j + 1;
      if (s[end] === '?' || s[end] === '+') end++;
      return { kind: 'bounded', variable: true, end };
    }
    if (c === '{') {
      const m = /^\{(\d+)(,(\d*))?\}/.exec(s.slice(j));
      if (m) {
        const lower = m[1];
        const hasComma = m[2] !== undefined;
        const upper = m[3];
        const unbounded = hasComma && (upper === undefined || upper === '');
        let variable;
        if (!hasComma) variable = false;            // {n} fixed
        else if (unbounded) variable = true;        // {n,}
        else variable = upper !== lower;            // {m,n} variable unless m==n
        let end = j + m[0].length;
        if (s[end] === '?' || s[end] === '+') end++;
        return { kind: unbounded ? 'unbounded' : 'bounded', variable, end };
      }
    }
    return { kind: 'none', variable: false, end: j };
  };
  const markAtomQuant = (q) => {
    const top = stack[stack.length - 1];
    if (q.kind === 'unbounded') { unboundedCount++; top.innerHeight = Math.max(top.innerHeight, 1); }
    if (q.variable) top.hasVar = true;
  };
  while (i < n) {
    const c = s[i];
    if (c === '\\') {
      const e = s[i + 1] || '';
      // Reject escapes the analyzer can't normalize (hex/unicode would hide a+a+ behind a)
      // and backreferences. Time/place patterns never need these.
      if (e === 'x' || e === 'u' || e === 'k' || (e >= '1' && e <= '9')) return false;
      const tok = '\\' + e;
      const j = i + 2;
      const q = readQuant(j);
      if (q.kind === 'unbounded' && prevAtom && prevAtom.unbounded && prevAtom.token === tok) return false;
      markAtomQuant(q);
      prevAtom = { token: tok, unbounded: q.kind === 'unbounded' };
      i = q.end > j ? q.end : j;
      continue;
    }
    if (c === '[') {
      let j = i + 1;
      if (s[j] === '^') j++;
      if (s[j] === ']') j++;
      while (j < n && s[j] !== ']') { if (s[j] === '\\') j++; j++; }
      if (j >= n) return false;                          // unterminated character class
      const tok = s.slice(i, j + 1);
      const k = j + 1;
      const q = readQuant(k);
      if (q.kind === 'unbounded' && prevAtom && prevAtom.unbounded && prevAtom.token === tok) return false;
      markAtomQuant(q);
      prevAtom = { token: tok, unbounded: q.kind === 'unbounded' };
      i = q.end > k ? q.end : k;
      continue;
    }
    if (c === '(') {
      stack.push({ alt: false, innerHeight: 0, hasVar: false });
      if (stack.length > 6) return false;
      let j = i + 1;
      if (s[j] === '?') {
        if (s[j + 1] === '<' && s[j + 2] !== '=' && s[j + 2] !== '!') {
          const gt = s.indexOf('>', j);
          j = gt < 0 ? n : gt + 1;
        } else {
          j += 2;
        }
      }
      prevAtom = null;
      i = j;
      continue;
    }
    if (c === '|') {
      stack[stack.length - 1].alt = true;
      prevAtom = null;
      i++;
      continue;
    }
    if (c === ')') {
      if (stack.length <= 1) return false;               // unbalanced ')'
      const frame = stack.pop();
      const parent = stack[stack.length - 1];
      const j = i + 1;
      const q = readQuant(j);
      let groupHeight;
      if (q.kind === 'unbounded') {
        unboundedCount++;
        if (frame.innerHeight >= 1) return false;        // nested unbounded (star height >= 2)
        if (frame.hasVar) return false;                  // variable quantifier inside unbounded group: (a{1,3})*, (ab?)*
        if (frame.alt) return false;                     // quantified alternation: (a|aa)*
        groupHeight = 1;
        parent.hasVar = true;
        prevAtom = { token: '(grp)', unbounded: true };
      } else {
        groupHeight = frame.innerHeight;                 // inner unbounded passes through
        if (q.variable) parent.hasVar = true;            // group is ?/{m,n}-quantified
        if (frame.hasVar) parent.hasVar = true;          // bubble inner variability up
        prevAtom = { token: '(grp)', unbounded: false };
      }
      parent.innerHeight = Math.max(parent.innerHeight, groupHeight);
      i = q.end > j ? q.end : (i + 1);
      continue;
    }
    const tok = c;
    const j = i + 1;
    const q = readQuant(j);
    if (q.kind === 'unbounded' && prevAtom && prevAtom.unbounded && prevAtom.token === tok) return false;
    markAtomQuant(q);
    prevAtom = { token: tok, unbounded: q.kind === 'unbounded' };
    i = q.end > j ? q.end : j;
  }
  if (stack.length !== 1) return false;                  // unbalanced '('
  if (unboundedCount > 12) return false;                 // overall complexity cap
  return true;
}

// Shared validator for agent-generated AND manually-entered extraction regexes (time/location).
// Returns a sanitized {regex, flags} or null. Strips g/y flags (they break single-match capture),
// caps length at 200, and runs the static ReDoS guard above (catastrophic backtracking defense).
// Classify a pattern's reliability from its STRUCTURE (not the LLM's self-label):
// numeric/bracketed/labelled notation = 'exact', a bare prose word = 'vague'.
// Strict RP date/time parsers — CODE normalizes (not the LLM). Vague words (저녁/밤) yield null on
// purpose; no year inference, no carry-forward. Used by extractMoment + datetime assembly.
function _rpPad2(n) { return String(n).padStart(2, '0'); }
function parseRpDate(label) {
  const s = String(label || '').trim();
  if (!s) return null;
  const m = s.match(/(\d{4})\s*[-./년]\s*(\d{1,2})\s*[-./월]\s*(\d{1,2})/);
  if (!m) return null;
  const y = +m[1], mo = +m[2], d = +m[3];
  if (y < 1900 || y > 2200 || mo < 1 || mo > 12 || d < 1 || d > 31) return null;
  return `${y}-${_rpPad2(mo)}-${_rpPad2(d)}`;
}
function parseRpTime(label) {
  const s = String(label || '').trim();
  if (!s) return null;
  let m = s.match(/(\d{1,2})\s*:\s*(\d{2})(?:\s*:\s*(\d{2}))?/);
  if (m) {
    let h = +m[1]; const min = +m[2]; const sec = m[3] != null ? +m[3] : null;
    if (/오후|p\.?\s*m\.?/i.test(s) && h < 12) h += 12;
    if (/오전|a\.?\s*m\.?/i.test(s) && h === 12) h = 0;
    if (h > 23 || min > 59 || (sec != null && sec > 59)) return null;
    return sec != null ? `${_rpPad2(h)}:${_rpPad2(min)}:${_rpPad2(sec)}` : `${_rpPad2(h)}:${_rpPad2(min)}`;
  }
  m = s.match(/(오전|오후)?\s*(\d{1,2})\s*시\s*(\d{1,2})?\s*분?/);
  if (m) {
    let h = +m[2]; const min = m[3] != null ? +m[3] : 0;
    if (m[1] === '오후' && h < 12) h += 12;
    if (m[1] === '오전' && h === 12) h = 0;
    if (h > 23 || min > 59) return null;
    return `${_rpPad2(h)}:${_rpPad2(min)}`;
  }
  return null;
}

// ─── RP stamp display (stage 3): lazy migration + format. Screen=Korean(ko), context=English. ───
function _rpAgo(ms, ko = false) {
  const mins = Math.floor(ms / 60000);
  if (mins < 60) return ko ? `${mins}분` : `${mins}m`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return ko ? `${hrs}시간` : `${hrs}h`;
  return ko ? `${Math.floor(hrs / 24)}일` : `${Math.floor(hrs / 24)}d`;
}
function _rpClockKo(timeLabel) {            // "20:03"/"20:03:36" → "오후 8:03"; non-clock → null
  const m = String(timeLabel || '').match(/^(\d{1,2}):(\d{2})/);
  if (!m) return null;
  const h = +m[1];
  return `${h >= 12 ? '오후' : '오전'} ${h % 12 || 12}:${m[2]}`;
}
function _rpDateKo(dateLabel) {              // "2026-03-24" → "2026년 3월 24일"; else null
  const m = String(dateLabel || '').match(/^(\d{4})-(\d{2})-(\d{2})/);
  return m ? `${m[1]}년 ${+m[2]}월 ${+m[3]}일` : null;
}
// Lazy stamp resolver: ts.rpCreated (stage2) or legacy label only — never invent datetime/turn.
function getRpStamp(item) {
  const rp = item?.ts?.rpCreated;
  if (rp) return rp;
  if (item?.source === 'backfill') return null;   // backfill legacy sessionTimeLabel = current-time pollution
  const label = item?.ts?.deliveredRpTime || item?.ts?.createdRpTime || item?.metadata?.sessionTimeLabel || null;
  if (!label) return null;
  return { datetimeIso: null, dateLabel: null, timeLabel: null, label, precision: 'time', turn: null, source: 'legacy' };
}
// itemStamp + curStamp → display. opts.ko = Korean (screen). opts.compact = relative-first (cards).
function formatRpStamp(itemStamp, curStamp = null, opts = {}) {
  if (!itemStamp) return '';
  const ko = !!opts.ko;
  const abs = (itemStamp.precision === 'datetime' && itemStamp.dateLabel && itemStamp.timeLabel)
    ? `${itemStamp.dateLabel} ${String(itemStamp.timeLabel).slice(0, 5)}`
    : (itemStamp.label || '');
  let rel = '';
  if (itemStamp.precision === 'datetime' && curStamp?.precision === 'datetime' && itemStamp.datetimeIso && curStamp.datetimeIso) {
    const d = Date.parse(curStamp.datetimeIso) - Date.parse(itemStamp.datetimeIso);
    if (Number.isFinite(d) && d > 0) rel = ko ? `${_rpAgo(d, true)} 전` : `${_rpAgo(d)} ago`;
  } else if (curStamp && Number.isFinite(curStamp.turn) && Number.isFinite(itemStamp.turn)) {
    const dt = curStamp.turn - itemStamp.turn;
    if (dt > 0) rel = ko ? `${dt}턴 전` : `${dt} turn${dt === 1 ? '' : 's'} ago`;
  }
  if (opts.compact) return rel || abs;
  return rel ? (abs ? `${abs} | ${rel}` : rel) : abs;
}
// DM group bucket: same RP moment (turn) = same group; null = unstamped → wall-clock 60s fallback.
function _dmBucket(msg) {
  const rp = msg?.ts?.rpCreated;
  if (rp) {
    if (Number.isFinite(rp.turn)) return `t${rp.turn}`;
    const k = rp.label || rp.timeLabel || rp.dateLabel;
    if (k) return k;
  }
  const s = msg?.ts?.deliveredRpTime || msg?.ts?.createdRpTime;
  return s ? `s${s}` : null;   // no usable RP key → wall-clock 60s fallback
}
// DM bubble/list clock — RP time only (timeLabel present); never a date-only stamp in the time slot.
function _dmClock(msg) {
  const rp = msg?.ts?.rpCreated;
  if (rp && rp.timeLabel) return _rpClockKo(rp.timeLabel) || rp.timeLabel;
  const s = msg?.ts?.deliveredRpTime || msg?.ts?.createdRpTime;
  if (s) return _rpClockKo(s) || s;
  const d = new Date(msg?.ts?.createdAt || Date.now());
  return `${d.getHours() >= 12 ? '오후' : '오전'} ${d.getHours() % 12 || 12}:${String(d.getMinutes()).padStart(2, '0')}`;
}
// DM date divider — RP date, or null (skip → keep prior) when stamped-but-no-date; wall-clock only if fully unstamped.
function _dmDate(msg) {
  const rp = msg?.ts?.rpCreated;
  if (rp) return _rpDateKo(rp.dateLabel);
  if (msg?.ts?.createdRpTime || msg?.ts?.deliveredRpTime) return null;
  const d = new Date(msg?.ts?.createdAt || Date.now());
  return `${d.getFullYear()}년 ${d.getMonth() + 1}월 ${d.getDate()}일`;
}

function classifyExtractConfidence(regex, kind) {
  const s = String(regex || '');
  if (kind === 'location') {
    return /(scene|location|place|장소|위치|지역|구역)/i.test(s) ? 'exact' : 'vague';
  }
  if (kind === 'date') {
    return (/(date|날짜|year|년|월|일)/i.test(s) || /\\d/.test(s) || /[0-9０-９]/.test(s)) ? 'exact' : 'vague';
  }
  // time: explicit label, or digits/bracket clock notation = exact; bare words = vague.
  // Digits count whether written as \d, a [0-9]/[０-９] range, or literal numerals in the pattern.
  if (/(scene|time|시각|시간|현재|날짜|date|기준|hour|turn|day)/i.test(s)) return 'exact';
  if (/\\d/.test(s) || /[0-9０-９]/.test(s) || /\\\[/.test(s)) return 'exact';
  return 'vague';
}

// Shared validator for agent-generated AND manually-entered extraction regexes (time/location).
// Strips g/y, caps length, runs the static ReDoS guard, rejects Hangul-adjacent \b (word boundary
// misfires on non-ASCII \w), and stamps a CODE-decided confidence (LLM's own label is not trusted).
// kind = 'time' | 'location'.
function validateExtractPattern(r, kind) {
  if (!r || typeof r !== 'object') return null;
  const regex = typeof r.regex === 'string' ? r.regex.trim() : '';
  if (!regex || regex.length > 200) return null;
  if (!isLinearTimeRegex(regex)) return null;
  if (/\\b/.test(regex) && /[가-힣]/.test(regex)) return null; // \b breaks on Hangul text
  let flags = '';
  if (typeof r.flags === 'string') {
    flags = [...new Set(r.flags.split(''))].filter(f => 'ims'.includes(f)).join('');
  }
  try { new RegExp(regex, flags); } catch { return null; }
  return { regex, flags, confidence: classifyExtractConfidence(regex, kind) };
}

class TimeTracker {
  constructor(store) {
    this.store = store;
    this.patterns = [];
    this.datePatterns = [];
    this.lastKnownTime = null;
    this.lastKnownMoment = null;   // { datetimeIso, dateLabel, timeLabel, label, precision }
    this.lastKnownTurn = null;     // cumulative non-user (assistant) turn count at last extract
    this.lastBackfillTurn = 0;
  }

  async init() {
    // Fallback chain: per-RP agent-authored patterns (store) > global custom (pluginStorage) > defaults.
    let applied = this.applyPatterns((this.store.get('watcher:extract:v3') || this.store.get('watcher:extract:v2'))?.time);
    if (!applied) {
      const stored = await Risuai.pluginStorage.getItem('time_patterns');
      if (stored) {
        try { applied = this.applyPatterns(JSON.parse(stored)); } catch { applied = false; }
      }
    }
    if (!applied) this.patterns = this._defaultPatterns();

    // Date patterns: v3 agent-authored date regexes (set by _generateExtractRegex) or built-in defaults.
    if (!this.applyDatePatterns(this.store.get('watcher:extract:v3')?.date)) {
      this.datePatterns = this._defaultDatePatterns();
    }

    const lbt = this.store.get('time:lastBackfillTurn');
    if (lbt) this.lastBackfillTurn = lbt;
  }

  applyPatterns(stored) {
    // Validate each {regex,flags,confidence} as time patterns (shared validator stamps confidence).
    // Returns true if >=1 valid pattern was applied; false lets the caller fall back.
    if (!Array.isArray(stored) || stored.length === 0) return false;
    const valid = stored.map(p => validateExtractPattern(p, 'time')).filter(Boolean).slice(0, 8);
    if (valid.length === 0) return false;
    this.patterns = valid;
    return true;
  }

  applyDatePatterns(stored) {
    if (!Array.isArray(stored) || stored.length === 0) return false;
    const valid = stored.map(p => validateExtractPattern(p, 'date')).filter(Boolean).slice(0, 8);
    if (valid.length === 0) return false;
    this.datePatterns = valid;
    return true;
  }

  _defaultPatterns() {
    return [
      { regex: '현재\\s*시간[:\\s]*(.+?)(?:\\n|$)', flags: 'i', confidence: 'exact' },
      { regex: 'Time[:\\s]*(.+?)(?:\\n|$)', flags: 'i', confidence: 'exact' },
      { regex: '\\[(\\d{1,2}:\\d{2}(?:\\s*[AP]M)?)\\]', flags: 'i', confidence: 'exact' },
      { regex: '((?:오전|오후)\\s*\\d{1,2}\\s*[:시]\\s*\\d{0,2}\\s*분?)', flags: '', confidence: 'exact' },
      { regex: '(\\d{1,2}시\\s*\\d{0,2}분?)', flags: '', confidence: 'exact' },
      { regex: '(오전|오후|아침|점심|저녁|밤|새벽)\\s*(\\d{1,2}시)?', flags: '', confidence: 'vague' },
    ];
  }

  _defaultDatePatterns() {
    return [
      { regex: '(?:Date|날짜)[:\\s]*([0-9]{4}\\s*[-./년]\\s*[0-9]{1,2}\\s*[-./월]\\s*[0-9]{1,2}\\s*일?)', flags: 'i', confidence: 'exact' },
      { regex: '([0-9]{4}\\s*[-./]\\s*[0-9]{1,2}\\s*[-./]\\s*[0-9]{1,2})', flags: '', confidence: 'exact' },
      { regex: '([0-9]{4}년\\s*[0-9]{1,2}월\\s*[0-9]{1,2}일)', flags: '', confidence: 'exact' },
    ];
  }

  _stripPluginContext(text) {
    return String(text || '')
      .replace(/(?:\[sns-context\]|\[sns_nai SNS\/Messenger Context - not dialogue\])[\s\S]*?(?:\[\/sns-context\]|\[\/sns_nai SNS\/Messenger Context\])/g, '')
      .replace(/^\[sns_nai SNS\/Messenger Data[^\]]*\][\s\S]*$/gm, '');
  }

  sanitizeDisplayTime(value) {
    const raw = String(value || '').trim();
    if (!raw || raw.length > 32 || /[\r\n<>{}]/.test(raw)) return null;
    if (/\b(sns_nai|Messenger|SNS|context|lore|entry|summary|profile|relationship|DM:|Post:)\b/i.test(raw)) return null;
    if (/(로어북|프로필|관계|요약|컨텍스트|메신저|포스트)/.test(raw)) return null;
    const compact = raw.replace(/\s+/g, ' ');
    const looksLikeTime = /(\d{1,2}\s*:\s*\d{2}|\d{1,2}\s*시\s*\d{0,2}\s*분?|오전|오후|아침|점심|저녁|밤|새벽|morning|afternoon|evening|night|noon|midnight|\b[ap]\.?m\.?\b)/i.test(compact);
    return looksLikeTime ? compact : null;
  }

  sanitizeDisplayDate(value) {
    const raw = String(value || '').trim();
    if (!raw || raw.length > 32 || /[\r\n<>{}]/.test(raw)) return null;
    if (/(로어북|프로필|관계|요약|컨텍스트|메신저|포스트)/.test(raw)) return null;
    const compact = raw.replace(/\s+/g, ' ');
    return /\d{4}\s*[-./년]\s*\d{1,2}/.test(compact) ? compact : null;  // must carry a 4-digit year
  }

  _scanGroups(text, groups, sanitize) {
    for (const group of groups) {
      for (const p of group) {
        try {
          const m = text.match(new RegExp(p.regex, p.flags));
          if (m) { const c = sanitize(m[1] || m[0]); if (c) return c; }
        } catch {}
      }
    }
    return null;
  }

  // Back-compat: returns the time label string only.
  extractTime(chatMessages) {
    const m = this.extractMoment(chatMessages);
    return m ? m.timeLabel : this.lastKnownTime;
  }

  // Full RP moment: date + time scanned independently (exact→vague) within the SAME newest message.
  // No carry-forward — if a message has no date, datetimeIso stays null (precision drops to time/vague).
  extractMoment(chatMessages) {
    if (!chatMessages || chatMessages.length === 0) return this.lastKnownMoment;
    const nonUser = chatMessages.filter(m => m.role !== 'user');
    this.lastKnownTurn = nonUser.length;
    const recent = nonUser.slice(-6);
    const tExact = this.patterns.filter(p => p.confidence !== 'vague');
    const tVague = this.patterns.filter(p => p.confidence === 'vague');
    const dExact = (this.datePatterns || []).filter(p => p.confidence !== 'vague');
    const dVague = (this.datePatterns || []).filter(p => p.confidence === 'vague');
    for (const msg of recent.reverse()) {
      // Keep head AND tail — status/footer blocks ("[ … | 2026-03-24 | 20:03 | … ]") sit at the end.
      const stripped = this._stripPluginContext(msg.data || '');
      const text = stripped.length <= 7000 ? stripped : (stripped.slice(0, 3000) + '\n…\n' + stripped.slice(-4000));
      const timeLabel = this._scanGroups(text, [tExact, tVague], v => this.sanitizeDisplayTime(v));
      const dateLabel = this._scanGroups(text, [dExact, dVague], v => this.sanitizeDisplayDate(v));
      if (!timeLabel && !dateLabel) continue;
      const date = dateLabel ? parseRpDate(dateLabel) : null;        // normalized "2026-03-24" | null
      const time = timeLabel ? parseRpTime(timeLabel) : null;        // normalized "20:03:36" | null (vague→null)
      const datetimeIso = (date && time) ? `${date}T${time}` : null;
      const precision = datetimeIso ? 'datetime' : (time ? 'time' : 'vague');
      const label = datetimeIso ? `${date} ${time}` : (time || timeLabel || date || dateLabel || null);
      const moment = { datetimeIso, dateLabel: date, timeLabel: (time || timeLabel || null), label, precision };
      this.lastKnownMoment = moment;
      if (timeLabel) this.lastKnownTime = timeLabel;
      return moment;
    }
    return this.lastKnownMoment;
  }

  // Full RP creation stamp for storage: extractMoment + assistant-turn count + source.
  // source 'extract' = fresh chat scanned now; 'cache' = last-known snapshot (sync provider path).
  // carry-forward note: when no time is found, m = lastKnownMoment (a PAST time label) but turn is the
  // CURRENT cumulative assistant-turn count — turn is always "now", so the mix is intentional.
  captureRpMoment(chatMessages = null) {
    if (chatMessages) {
      const m = this.extractMoment(chatMessages);
      const turn = chatMessages.filter(x => x.role !== 'user').length;
      return m ? { ...m, turn, source: 'extract' }
               : { datetimeIso: null, dateLabel: null, timeLabel: null, label: null, precision: 'vague', turn, source: 'extract' };
    }
    const m = this.lastKnownMoment;
    const turn = this.lastKnownTurn;
    return m ? { ...m, turn, source: 'cache' }
             : { datetimeIso: null, dateLabel: null, timeLabel: null, label: null, precision: 'vague', turn, source: 'cache' };
  }

  getElapsedInfo(chatMessages) {
    const currentTime = this.extractTime(chatMessages);
    const turnsSinceBackfill = (chatMessages?.length || 0) - this.lastBackfillTurn;
    return { currentTime, turnsSinceBackfill };
  }

  markBackfilled(chatMessages) {
    this.lastBackfillTurn = chatMessages?.length || 0;
    this.store.set('time:lastBackfillTurn', this.lastBackfillTurn);
    const moment = this.captureRpMoment(chatMessages);
    if (moment?.datetimeIso) {
      this.store.set('time:lastBackfillMoment', moment);
    }
  }
}

// ============================================================================
//  TimelineGenerator — Lazy backfill
// ============================================================================

class TimelineGenerator {
  constructor(generator, posts, profiles, timeTracker) {
    this.generator = generator;
    this.posts = posts;
    this.profiles = profiles;
    this.timeTracker = timeTracker;
    this.progress = null;
  }

  _formatBackfillRpDate(date) {
    const dateLabel = `${date.getFullYear()}-${_rpPad2(date.getMonth() + 1)}-${_rpPad2(date.getDate())}`;
    const timeLabel = `${_rpPad2(date.getHours())}:${_rpPad2(date.getMinutes())}:${_rpPad2(date.getSeconds())}`;
    return {
      datetimeIso: `${dateLabel}T${timeLabel}`,
      dateLabel,
      timeLabel,
      label: `${dateLabel} ${timeLabel}`,
    };
  }

  _deriveBackfillRpTurn(currentMoment, offsetMs, hoursPerTurn) {
    const currentTurn = Number(currentMoment?.turn);
    const hpt = Number(hoursPerTurn);
    if (!Number.isFinite(currentTurn) || currentTurn <= 0) return null;
    if (!Number.isFinite(offsetMs) || offsetMs <= 0) return null;
    if (!Number.isFinite(hpt) || hpt <= 0) return null;
    const turnDelta = Math.max(1, Math.round((offsetMs / 3600000) / hpt));
    if (!Number.isFinite(turnDelta) || turnDelta <= 0) return null;
    return Math.max(0, Math.round(currentTurn) - turnDelta);
  }

  _deriveBackfillRpMoment(currentMoment, publishedAt, now, opts = {}) {
    try {
      if (!currentMoment || typeof currentMoment !== 'object') return null;
      const offsetMs = Number(now) - Number(publishedAt);
      if (!Number.isFinite(offsetMs) || offsetMs <= 0) return null;
      const shiftedTurn = this._deriveBackfillRpTurn(currentMoment, offsetMs, opts.hoursPerTurn);

      if (currentMoment.precision === 'datetime' && currentMoment.datetimeIso) {
        const baseMs = Date.parse(currentMoment.datetimeIso);
        if (!Number.isFinite(baseMs)) return null;
        const shifted = new Date(baseMs - offsetMs);
        if (!Number.isFinite(shifted.getTime())) return null;
        return {
          ...currentMoment,
          ...this._formatBackfillRpDate(shifted),
          precision: 'datetime',
          turn: Number.isFinite(shiftedTurn) ? shiftedTurn : null,
          source: 'backfill',
        };
      }

      if (!Number.isFinite(shiftedTurn)) {
        const hasLabel = currentMoment.label || currentMoment.timeLabel || currentMoment.dateLabel;
        if (!hasLabel) return null;
        return {
          ...currentMoment,
          turn: null,
          source: 'backfill',
        };
      }
      return {
        ...currentMoment,
        turn: shiftedTurn,
        source: 'backfill',
      };
    } catch {
      return null;
    }
  }

  async generateBackfill(chatMessages, onProgress, hoursElapsed = null, userPrefs = {}) {
    if (hoursElapsed === null || hoursElapsed <= 0) return [];

    const allProfiles = Object.values(this.profiles.getAll()).filter(p => !p.isUser && isSnsEligible(p));
    if (allProfiles.length === 0) return [];

    const _pph = parseFloat(await Risuai.pluginStorage.getItem('posts_per_hour'));
    const postsPerHour = Number.isFinite(_pph) ? _pph : 1.5;
    const _hpt = parseFloat(await Risuai.pluginStorage.getItem('hours_per_turn'));
    const hoursPerTurn = Number.isFinite(_hpt) && _hpt > 0 ? _hpt : 1.0;
    const postsToGenerate = Math.min(
      Math.ceil(hoursElapsed * postsPerHour),
      allProfiles.length * 2,
      10
    );

    if (postsToGenerate <= 0) return [];

    const progressTask = this.progress?.startTask(
      this.progress.createTaskId('backfill'),
      '타임라인 생성 중...',
      postsToGenerate
    );

    try {
    const generated = [];
    const plans = [];
    const timeRange = hoursElapsed * 3600000;
    const now = Date.now();
    let bridgeData = null;
    let backfillMessages = Array.isArray(chatMessages) ? chatMessages : [];

    try {
      const charIdx = await Risuai.getCurrentCharacterIndex();
      const chatIdx = await Risuai.getCurrentChatIndex();
      const chat = await Risuai.getChatFromIndex(charIdx, chatIdx);
      const char = await Risuai.getCharacter();
      bridgeData = { char, charIdx, chatIdx, chat };
      if (Array.isArray(chat?.message) && chat.message.length > 0) backfillMessages = chat.message;
    } catch (e) {
      console.warn('[sns_nai] Backfill bridge prefetch failed:', e.message);
    }

    let currentRpMoment = null;
    try {
      currentRpMoment = this.timeTracker?.captureRpMoment?.(backfillMessages) ?? null;
    } catch {
      currentRpMoment = null;
    }

    if (this.generator.eventExtractor?.extract) {
      try {
        await this.generator.eventExtractor.extract(backfillMessages);
      } catch (e) {
        console.warn('[sns_nai] Backfill event extraction failed:', e.message);
      }
    }

    const fallbackDecision = (requestedPlatform = null) => {
      const author = allProfiles[Math.floor(Math.random() * allProfiles.length)];
      const platform = ACTIVE_SNS_PLATFORMS.includes(requestedPlatform)
        ? requestedPlatform
        : ['twitter', 'instagram'][Math.floor(Math.random() * 2)];
      return {
        platform,
        authorId: author.pkey,
        accountMode: 'main',
      };
    };

    const makePlan = (decision, requestedPlatform) => {
      if (!decision || typeof decision !== 'object') return null;
      const requestedAuthor = decision.authorId || decision.author;
      const resolved = this.profiles.resolve?.(requestedAuthor)
        || allProfiles.find(p => p.pkey === requestedAuthor || p.realname === requestedAuthor);
      if (!resolved || resolved.isUser || !isSnsEligible(resolved)) return null;
      const platform = ACTIVE_SNS_PLATFORMS.includes(decision.platform)
        ? decision.platform
        : (ACTIVE_SNS_PLATFORMS.includes(requestedPlatform) ? requestedPlatform : 'twitter');
      const offset = Math.random() * timeRange;
      return {
        platform,
        authorId: resolved.pkey,
        directive: decision.directive || decision.topic || '',
        mood: decision.mood || '',
        suggestedNsfwLevel: decision.suggestedNsfwLevel || decision.nsfwLevel || undefined,
        accountId: decision.accountId || null,
        accountMode: decision.accountMode || undefined,
        subIdentity: decision.subIdentity || undefined,
        publishedAt: now - timeRange + offset,
      };
    };

    const normalizedPrefs = {
      ...userPrefs,
      nsfwOverride: normalizeNsfwOverride(userPrefs?.nsfwOverride) ?? userPrefs?.nsfwOverride,
    };
    const seenPlanKeys = new Set();

    for (let i = 0; i < postsToGenerate; i++) {
      progressTask?.update({ current: i + 1, total: postsToGenerate, label: '타임라인 계획 중...' });
      if (onProgress) onProgress(`타임라인 계획 중... (${i + 1}/${postsToGenerate})`);

      const requestedPlatform = ACTIVE_SNS_PLATFORMS.includes(userPrefs?.platform)
        ? userPrefs.platform
        : ['twitter', 'instagram'][Math.floor(Math.random() * 2)];
      let decision = null;
      try {
        decision = await this.generator.autoDirector(requestedPlatform, normalizedPrefs);
      } catch (e) {
        console.error('[sns_nai] Backfill autoDirector failed:', e.message);
      }

      let plan = makePlan(decision, requestedPlatform) || makePlan(fallbackDecision(requestedPlatform), requestedPlatform);
      if (plan) {
        const planKey = `${plan.authorId}|${plan.platform}|${String(plan.directive || '').toLowerCase().slice(0, 80)}`;
        if (seenPlanKeys.has(planKey)) {
          plan = makePlan(fallbackDecision(requestedPlatform), requestedPlatform) || plan;
        }
        seenPlanKeys.add(`${plan.authorId}|${plan.platform}|${String(plan.directive || '').toLowerCase().slice(0, 80)}`);
        plans.push(plan);
      }
    }

    const _concurrency = parseInt(await Risuai.pluginStorage.getItem('backfill_concurrency'), 10);
    const concurrency = Number.isFinite(_concurrency) && _concurrency > 0 ? _concurrency : 3;
    const sem = new SrSemaphore(concurrency);
    let completed = 0;
    const results = await Promise.allSettled(plans.map((plan) => sem.run(async () => {
      try {
        return await this.generator.generatePost({
          platform: plan.platform,
          authorId: plan.authorId,
          directive: plan.directive,
          mood: plan.mood,
          suggestedNsfwLevel: plan.suggestedNsfwLevel,
          accountId: plan.accountId,
          accountMode: plan.accountMode,
          subIdentity: plan.subIdentity,
          publishedAt: plan.publishedAt,
          rpCreated: this._deriveBackfillRpMoment(currentRpMoment, plan.publishedAt, now, { hoursPerTurn }),
          source: 'backfill',
          _cachedBridgeData: bridgeData,
        });
      } finally {
        completed++;
        progressTask?.update({ current: completed, total: plans.length, label: '타임라인 생성 중...' });
        if (onProgress) onProgress(`타임라인 생성 중... (${completed}/${plans.length})`);
      }
    })));

    results.forEach((result, i) => {
      if (result.status === 'fulfilled') {
        if (result.value) generated.push(result.value);
      } else {
        const plan = plans[i];
        console.error(`[sns_nai] Backfill error for ${plan?.authorId || 'unknown'}:`, result.reason?.message || result.reason);
      }
    });

    if (plans.length === 0) {
      progressTask?.update({ current: postsToGenerate, total: postsToGenerate, label: '타임라인 생성 중...' });
    }

    this.timeTracker.markBackfilled(backfillMessages);
    return generated.sort((a, b) => (a.publishedAt ?? 0) - (b.publishedAt ?? 0));
    } finally {
      progressTask?.complete();
    }
  }
}

// ============================================================================
//  MainModelIntegrator
// ============================================================================

class MainModelIntegrator {
  constructor(posts, rooms, profiles, watcher, accountRegistry = null, opts = {}) {
    this.posts = posts;
    this.rooms = rooms;
    this.profiles = profiles;
    this.watcher = watcher;
    this.accountRegistry = accountRegistry;
    this.memorizer = opts.memorizer || null;
    this.timeTracker = opts.timeTracker || null;
    this.contextConfig = opts.contextConfig || {};
  }

  buildContextSummary(watchResult, ageHours = 24) {
    const sections = [];
    const curStamp = this.timeTracker?.captureRpMoment?.() ?? null;
    const cutoff = Date.now() - (ageHours * 3600000);
    const dmPerRoomMin = 10;
    const dmPerRoomMax = 20;
    const dmRoomLimit = 5;
    const formatHiddenContext = (hidden) => {
      if (!hidden || typeof hidden !== 'object') return '';
      const quote = (value, limit = 120) => this._clipContextText(value, limit).replace(/"/g, '\\"');
      const parts = [];
      if (hidden.intent) parts.push(`intent="${quote(hidden.intent)}"`);
      if (hidden.triggerEvent) parts.push(`trigger="${quote(hidden.triggerEvent)}"`);
      return parts.length > 0 ? ` [hidden: ${parts.join(', ')}]` : '';
    };

    const allRecent = this.posts.listPosts(null, 30)
      .filter(p => (p.publishedAt ?? p.ts?.createdAt ?? 0) > cutoff);
    const canonPosts = allRecent.filter(p => p.canonMode === 'canon' || (p.canonMode === 'agent' && p.canonStatus === 'committed')).slice(0, 3);
    // Exclude unresolved and rejected agent posts — only committed agents included above
    const recentPosts = canonPosts.slice(0, 5);
    if (recentPosts.length > 0) {
      const lines = [];
      for (const p of recentPosts) {
        const prof = this.profiles?.resolve(p.author);
        const profileId = p.authorId || prof?.pkey || p.author;
        const mainAcc = this.accountRegistry?.getMain(profileId);
        const handle = mainAcc?.handle || prof?.handles?.twitter || profileId;
        const st = formatRpStamp(getRpStamp(p), curStamp);
        const hiddenContext = formatHiddenContext(p.metadata?.hidden);
        lines.push(`- ${st ? st + ', ' : ''}@${handle} posted: "${this._clipContextText(p.body, 160)}"${hiddenContext}`);
      }
      sections.push(`Recent SNS:\n${lines.join('\n')}`);
    }

    const rooms = this.rooms.listRooms();
    const dmRooms = [];
    for (const r of rooms) {
      const room = this.rooms.peekRoom ? this.rooms.peekRoom(r.id) : this.rooms.getRoom(r.id);
      if (!room) continue;

      const getContextMessages = this.rooms.getLatestContextMessages || this.rooms.getLatestMessages;
      const delivered = getContextMessages.call(this.rooms, r.id, Math.max(50, dmPerRoomMax))
        .filter(m => this._isDeliveredContextMessage(m));
      if (delivered.length === 0) continue;

      const latestTs = Math.max(...delivered.map(m => this._dmMsgTs(m) || room.lastTs || 0));
      if (!latestTs || latestTs <= cutoff) continue;

      const selected = delivered.slice(-Math.min(dmPerRoomMax, Math.max(dmPerRoomMin, delivered.length)));
      dmRooms.push({
        latestTs,
        section: this._formatDMRoomContext(room, selected),
      });
    }

    dmRooms
      .sort((a, b) => b.latestTs - a.latestTs)
      .slice(0, dmRoomLimit)
      .forEach(entry => { if (entry.section) sections.push(entry.section); });

    if (sections.length === 0) return null;

    const headerTime = (curStamp?.precision === 'datetime' && curStamp.dateLabel && curStamp.timeLabel)
      ? `${curStamp.dateLabel} ${String(curStamp.timeLabel).slice(0, 5)}`
      : (watchResult?.time || curStamp?.label || this.timeTracker?.sanitizeDisplayTime?.(this.timeTracker?.lastKnownTime) || '');
    const loc = watchResult?.location || '';
    const header = [
      'Background SNS/messenger state (not dialogue) — reflect only if it would naturally affect the character.',
      headerTime ? `Current time: ${headerTime}` : '',
      loc ? `Current location: ${loc}` : '',
    ].filter(Boolean);
    return `${header.join('\n')}\n\n${sections.join('\n\n')}`;
  }

  _isDeliveredContextMessage(msg) {
    return !!msg && msg.visible !== false && (!msg.state || msg.state === 'delivered');
  }

  _dmMsgTs(msg) {
    return msg?.ts?.deliveredAt || msg?.ts?.createdAt || 0;
  }

  _dmRpTime(msg) {
    return msg?.ts?.rpCreated?.label || msg?.ts?.deliveredRpTime || msg?.ts?.createdRpTime || '';
  }

  _wallClockLabel(ts) {
    if (!ts) return '';
    const d = new Date(ts);
    const h = d.getHours();
    const m = String(d.getMinutes()).padStart(2, '0');
    return `${h >= 12 ? '오후' : '오전'} ${h % 12 || 12}:${m}`;
  }

  _dmTimeLabel(msg) {
    return this._dmRpTime(msg) || '';   // RP only — unstamped → '' → 'unknown time' (no wall-clock invent)
  }

  _senderLabel(sender) {
    const prof = this.profiles?.resolve?.(sender);
    return prof?.realname || sender || 'unknown';
  }

  _clipContextText(value, limit = 180) {
    const text = String(value || '').replace(/\s+/g, ' ').trim();
    if (text.length <= limit) return text;
    return `${text.slice(0, Math.max(0, limit - 1)).trimEnd()}…`;
  }

  _formatDMMessageLine(room, msg) {
    const sender = this._senderLabel(msg.sender);
    const body = (msg.body || '').trim();
    const media = msg.media
      ? `[${msg.media.type || 'media'}:${msg.media.description || msg.media.fileName || 'attachment'}]`
      : '';
    const text = this._clipContextText(body || media || '[empty]', 180);
    return `  - ${sender}: "${text}"`;
  }

  _groupDMMessages(messages) {
    const groups = [];
    for (const msg of messages || []) {
      const ts = this._dmMsgTs(msg);
      const rpTime = this._dmRpTime(msg);
      const prev = groups[groups.length - 1];
      const prevMsg = prev?.messages?.[prev.messages.length - 1];
      const prevTs = prevMsg ? this._dmMsgTs(prevMsg) : 0;
      const prevRpTime = prevMsg ? this._dmRpTime(prevMsg) : '';
      const rpTurn = msg?.ts?.rpCreated?.turn;
      const prevRpTurn = prevMsg?.ts?.rpCreated?.turn;
      const sameRpTime = (Number.isFinite(rpTurn) && Number.isFinite(prevRpTurn))
        ? rpTurn === prevRpTurn
        : (rpTime && prevRpTime && rpTime === prevRpTime);
      const closeWallClock = ts && prevTs && Math.abs(ts - prevTs) <= 180000;
      const canUseWallClockGrouping = !rpTime && !prevRpTime;
      if (prev && (sameRpTime || (canUseWallClockGrouping && closeWallClock))) {
        prev.messages.push(msg);
        continue;
      }
      groups.push({ timeLabel: this._dmTimeLabel(msg), messages: [msg] });
    }
    return groups;
  }

  _formatDMRoomContext(room, messages) {
    if (!room || !messages?.length) return '';
    const title = room.title || room.id;
    const mode = room.mode === 'group' ? 'group chat'
      : room.mode === 'observer_dm' ? 'bot-to-bot 1:1 chat'
      : '1:1 chat';
    const lines = [`Messenger room "${title}" (${mode}):`];
    const summary = this.memorizer?.getDMSummary?.(room.id)?.summary;
    if (summary) lines.push(`Summary: ${this._clipContextText(summary, 420)}`);
    lines.push(`Recent messages (${messages.length}, chronological):`);
    for (const group of this._groupDMMessages(messages)) {
      const label = group.timeLabel || 'unknown time';
      lines.push(`- Around ${label}:`);
      for (const msg of group.messages) {
        lines.push(this._formatDMMessageLine(room, msg));
      }
    }
    return lines.join('\n');
  }
}

// ============================================================================
//  XView — X (Twitter) Platform View
// ============================================================================

function escHtml(s) {
  if (!s) return '';
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');
}

const SR_IMAGE_SRC_CACHE = new Map();

async function srImageDataToSrc(data, mimeType = 'image/png') {
  if (typeof data === 'string') {
    const text = data.trim();
    if (!text) return '';
    if (/^(data:|blob:|https?:)/i.test(text)) return text;
    return `data:${mimeType || 'image/png'};base64,${text.replace(/\s+/g, '')}`;
  }
  if (typeof Blob !== 'undefined' && data instanceof Blob) {
    return URL.createObjectURL(data);
  }
  const bytes = srBytesFromByteLike(data);
  if (!bytes) return '';
  return URL.createObjectURL(new Blob([bytes], { type: mimeType || 'image/png' }));
}

async function readSrImageData(assetPath) {
  const bytes = srBytesFromByteLike(assetPath);
  if (bytes) return bytes;
  const path = srNormalizeAssetPath(assetPath) || (typeof assetPath === 'string' ? assetPath.trim() : '');
  if (!path) return null;
  // v6.9 srimg path: SafeLocalPluginStorage backend, base64 single-record (legacy fallback 보존)
  if (parseSrImgPath(path)) {
    try {
      const cachedBlob = _srBlobCache.get(path);
      if (cachedBlob && typeof cachedBlob.arrayBuffer === 'function') {
        return new Uint8Array(await cachedBlob.arrayBuffer());
      }
      const store = await getSrImageStore();
      const value = await store.getItem(path);
      if (!value) return null;
      // v6.9 primary: base64 string
      if (typeof value.bytesB64 === 'string' && value.bytesB64) {
        const u8 = srBase64ToBytes(value.bytesB64);
        if (u8) {
          _srBlobCache.set(path, new Blob([u8.slice()], { type: value.mime || 'image/png' }));
          return u8;
        }
      }
      // legacy v7: plain Array<number> chunks + manifest
      if (value.kind === 'plainChunks') {
        const chunkBytes = await srReadImageChunksAsBytes(store, path, value);
        if (chunkBytes) {
          _srBlobCache.set(path, new Blob([chunkBytes], { type: value.mime || 'image/png' }));
          return chunkBytes;
        }
      }
      // legacy v6.4/6.5: top-level bytes-like object
      const topBytes = srBytesFromByteLike(value);
      if (topBytes) {
        _srBlobCache.set(path, new Blob([topBytes], { type: 'image/png' }));
        return topBytes;
      }
      // legacy v6.8: top-level Blob (realm-cross instanceof unsafe → duck-typing)
      if (typeof value.arrayBuffer === 'function') {
        _srBlobCache.set(path, value);
        return new Uint8Array(await value.arrayBuffer());
      }
      // legacy v6.7: nested {blob}
      if (value.blob && typeof value.blob.arrayBuffer === 'function') {
        _srBlobCache.set(path, value.blob);
        return new Uint8Array(await value.blob.arrayBuffer());
      }
      // legacy v6.4/6.5: nested bytes field
      if (value.bytes != null) {
        const u8 = srBytesFromByteLike(value.bytes);
        if (u8) {
          _srBlobCache.set(path, new Blob([u8.slice()], { type: value.mime || 'image/png' }));
          return new Uint8Array(u8);
        }
      }
      // legacy v6.3: plain-object-coerced blob field
      if (value.blob != null) {
        const u8 = srBytesFromByteLike(value.blob);
        if (u8) {
          _srBlobCache.set(path, new Blob([u8.slice()], { type: value.mime || 'image/png' }));
          return new Uint8Array(u8);
        }
      }
      return null;
    } catch (e) {
      console.warn('[sns_nai] readSrImageData srimg failed:', e?.message);
      return null;
    }
  }
  if (typeof Risuai === 'undefined' || !Risuai.readImage) return null;
  return Risuai.readImage(path);
}

async function readSrImageBlob(assetPath, mimeType = 'image/png') {
  const path = srNormalizeAssetPath(assetPath) || (typeof assetPath === 'string' ? assetPath.trim() : '');
  if (!parseSrImgPath(path)) return null;
  const cachedBlob = _srBlobCache.get(path);
  if (cachedBlob && typeof cachedBlob.arrayBuffer === 'function') return cachedBlob;
  const store = await getSrImageStore();
  const value = await store.getItem(path);
  if (!value) return null;
  // v6.9 primary: base64
  if (typeof value.bytesB64 === 'string' && value.bytesB64) {
    const u8 = srBase64ToBytes(value.bytesB64);
    if (u8) {
      const blob = new Blob([u8.slice()], { type: value.mime || mimeType || 'image/png' });
      _srBlobCache.set(path, blob);
      return blob;
    }
  }
  // legacy v7: plainChunks
  if (value.kind === 'plainChunks') {
    const chunkBytes = await srReadImageChunksAsBytes(store, path, value);
    if (chunkBytes) {
      const blob = new Blob([chunkBytes], { type: value.mime || mimeType || 'image/png' });
      _srBlobCache.set(path, blob);
      return blob;
    }
  }
  // legacy v6.4/6.5: top-level bytes
  const topBytes = srBytesFromByteLike(value);
  if (topBytes) {
    const blob = new Blob([topBytes], { type: mimeType || 'image/png' });
    _srBlobCache.set(path, blob);
    return blob;
  }
  // legacy v6.8: top-level Blob (duck-typing)
  if (typeof value.arrayBuffer === 'function') {
    _srBlobCache.set(path, value);
    return value;
  }
  // legacy v6.7: nested {blob}
  if (value.blob && typeof value.blob.arrayBuffer === 'function') {
    _srBlobCache.set(path, value.blob);
    return value.blob;
  }
  // legacy v6.4/6.5/6.3: nested bytes/blob
  const bytes = value.bytes != null
    ? srBytesFromByteLike(value.bytes)
    : (value.blob != null ? srBytesFromByteLike(value.blob) : null);
  if (bytes) {
    const blob = new Blob([bytes.slice()], { type: value.mime || mimeType || 'image/png' });
    _srBlobCache.set(path, blob);
    return blob;
  }
  return null;
}

async function readSrImageSrc(assetPath, mimeType = 'image/png') {
  const bytes = srBytesFromByteLike(assetPath);
  if (bytes) return srImageDataToSrc(bytes, mimeType);
  const path = srNormalizeAssetPath(assetPath) || (typeof assetPath === 'string' ? assetPath.trim() : '');
  if (!path) return '';
  // Plan v6.3: srimg는 store에서 읽음. legacy assets/는 Risuai.readImage 필요
  if (!parseSrImgPath(path) && (typeof Risuai === 'undefined' || !Risuai.readImage)) return '';
  const cacheKey = `${path}\u0000${mimeType || 'image/png'}`;
  let cached = SR_IMAGE_SRC_CACHE.get(cacheKey);
  if (!cached) {
    cached = parseSrImgPath(path)
      ? readSrImageBlob(path, mimeType).then(blob => blob ? URL.createObjectURL(blob) : '')
      : readSrImageData(path).then(data => srImageDataToSrc(data, mimeType));
    SR_IMAGE_SRC_CACHE.set(cacheKey, cached);
  }
  try {
    const src = await cached;
    if (!src) {
      // v6.6: 빈 결과 캐시 고정 회피 — 첫 hydration race 시 store 미준비로 null/'' 반환되면
      // Promise가 캐시에 박혀 후속 호출 모두 '' 반환되는 race 차단. 다음 호출은 cache miss로 재시도.
      SR_IMAGE_SRC_CACHE.delete(cacheKey);
      return '';
    }
    SR_IMAGE_SRC_CACHE.set(cacheKey, src);
    if (typeof src === 'string' && src.startsWith('blob:')) {
      srImgRegisterBlobUrl(path, src);
    }
    return src;
  } catch {
    SR_IMAGE_SRC_CACHE.delete(cacheKey);
    return '';
  }
}

async function loadSrImageInto(img, assetPath, mimeType = 'image/png') {
  if (!img) return '';
  const src = await readSrImageSrc(assetPath, mimeType);
  if (src) {
    img.style.opacity = '0';
    img.style.transition = 'opacity 0.3s ease';
    const reveal = () => { img.style.opacity = '1'; };
    img.addEventListener('load', reveal, { once: true });
    img.addEventListener('error', reveal, { once: true });
    img.src = src;
  }
  return src;
}

function createSrActionEmptyState({ title = '', message = '', actions = [] } = {}) {
  const wrap = document.createElement('div');
  wrap.className = 'sr-action-empty';
  if (title) {
    const titleEl = document.createElement('div');
    titleEl.className = 'sr-action-empty-title';
    titleEl.textContent = title;
    wrap.appendChild(titleEl);
  }
  if (message) {
    const msgEl = document.createElement('div');
    msgEl.className = 'sr-action-empty-message';
    msgEl.textContent = message;
    wrap.appendChild(msgEl);
  }
  const validActions = (actions || []).filter(action => action?.label && typeof action.onClick === 'function');
  if (validActions.length > 0) {
    const row = document.createElement('div');
    row.className = 'sr-action-empty-actions';
    for (const action of validActions) {
      const btn = document.createElement('button');
      btn.type = 'button';
      btn.className = `sr-empty-action${action.primary ? ' primary' : ''}`;
      btn.textContent = action.label;
      btn.addEventListener('click', (e) => {
        e.preventDefault();
        e.stopPropagation();
        action.onClick(e);
      });
      row.appendChild(btn);
    }
    wrap.appendChild(row);
  }
  return wrap;
}

function createCrossPlatformProfileLinks({ registry, profileId, currentPlatform, currentAccount, onNavigate } = {}) {
  if (!registry || !profileId || !currentPlatform || !currentAccount || typeof onNavigate !== 'function') return null;
  const platformOrder = ACTIVE_SNS_PLATFORMS;
  const accounts = registry.getByProfile?.(profileId) || [];
  const isUserAccount = currentAccount.type === 'user';
  const canReveal = (target) => {
    if (!target || target.id === currentAccount.id || target.platform === currentPlatform) return false;
    if (target.type === 'user' || isUserAccount) return true;
    return currentAccount.identityPolicy === 'open' && target.identityPolicy === 'open';
  };
  const byPlatform = [];
  for (const platform of platformOrder) {
    if (platform === currentPlatform) continue;
    const candidates = accounts
      .filter(a => a?.platform === platform && a.type !== 'stub' && a.status === 'active')
      .sort((a, b) => (a.type === 'main' ? -1 : 0) - (b.type === 'main' ? -1 : 0));
    const target = candidates.find(canReveal);
    if (target) byPlatform.push(target);
  }
  if (byPlatform.length === 0) return null;

  const wrap = document.createElement('div');
  wrap.className = 'sr-cross-links';
  const label = document.createElement('span');
  label.className = 'sr-cross-link-label';
  label.textContent = '다른 SNS';
  wrap.appendChild(label);
  for (const acc of byPlatform) {
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = `sr-cross-link-chip ${acc.platform}`;
    btn.textContent = `${accountPlatformLabel(acc.platform)} @${acc.handle || acc.displayName || acc.slot || 'account'}`;
    btn.addEventListener('click', (e) => {
      e.preventDefault();
      e.stopPropagation();
      onNavigate(acc.platform, acc.id);
    });
    wrap.appendChild(btn);
  }
  return wrap;
}

function normalizeSnsHandle(handle) {
  return String(handle || '').trim().replace(/^@+/, '').toLowerCase();
}

function resolveAccountByHandle(registry, handle, platform = null) {
  const needle = normalizeSnsHandle(handle);
  if (!registry || !needle) return null;
  return (registry.getAll?.() || []).find(acc => {
    if (!acc || acc.status !== 'active' || acc.type === 'stub') return false;
    if (platform && acc.platform !== platform) return false;
    return normalizeSnsHandle(acc.handle) === needle;
  }) || null;
}

function appendWithHashtags(parent, text) {
  // Render inline #hashtags as blue spans (plain text otherwise). Negative lookbehind blocks a #
  // that follows a word char (영숫자/한글/_), so mid-word #s like 안녕#태그 or abc#tag are NOT styled —
  // only a # after a space/punctuation/line-start becomes a tag, matching how X/IG detect hashtags.
  // (\w in JS excludes Hangul, so 가-힣 is listed explicitly.)
  const raw = String(text || '');
  const hashRe = /(?<![A-Za-z0-9_가-힣])#([A-Za-z0-9_가-힣]{1,50})/g;
  let last = 0;
  let m;
  while ((m = hashRe.exec(raw))) {
    if (m.index > last) parent.appendChild(document.createTextNode(raw.slice(last, m.index)));
    const tag = document.createElement('span');
    tag.className = 'sr-hashtag';
    tag.textContent = m[0];
    parent.appendChild(tag);
    last = m.index + m[0].length;
  }
  if (last < raw.length) parent.appendChild(document.createTextNode(raw.slice(last)));
}

function appendTextWithMentions(parent, text, { registry = null, platform = null, onNavigateProfile = null } = {}) {
  if (!parent) return;
  const raw = String(text || '');
  const mentionRe = /(^|[^\w@])@([A-Za-z0-9_][A-Za-z0-9_.]{0,29})/g;
  let last = 0;
  let match;
  while ((match = mentionRe.exec(raw))) {
    const mentionStart = match.index + match[1].length;
    if (mentionStart > last) appendWithHashtags(parent, raw.slice(last, mentionStart));
    const handle = match[2];
    const account = resolveAccountByHandle(registry, handle, platform);
    const link = document.createElement('button');
    link.type = 'button';
    link.className = 'sr-mention-link';
    link.textContent = `@${handle}`;
    if (account && typeof onNavigateProfile === 'function') {
      link.addEventListener('click', (e) => {
        e.preventDefault();
        e.stopPropagation();
        onNavigateProfile(account.id);
      });
    } else {
      link.disabled = true;
      link.classList.add('unresolved');
    }
    parent.appendChild(link);
    last = mentionStart + handle.length + 1;
  }
  if (last < raw.length) appendWithHashtags(parent, raw.slice(last));
}

// Debug post editor modal. Shared by XView/IGView/OFView/FeedUI — takes the PostManager
// so it can persist via pm.updatePostFields. Submits FULL hidden/poll objects so the
// shallow metadata merge in updatePostFields never drops sibling nested fields.
function showPostEditModal(post, pm, onSaved) {
  if (!post || !pm) return;
  document.querySelectorAll('.sr-edit-overlay').forEach(el => el.remove());
  const overlay = document.createElement('div');
  overlay.className = 'sr-overlay sr-edit-overlay';
  const modal = document.createElement('div');
  modal.className = 'sr-edit-modal';
  overlay.appendChild(modal);

  const header = document.createElement('div');
  header.className = 'sr-edit-header';
  header.textContent = '포스트 수정 (디버그)';
  modal.appendChild(header);

  const bodyWrap = document.createElement('div');
  bodyWrap.className = 'sr-edit-body';
  modal.appendChild(bodyWrap);

  const section = (title) => {
    const s = document.createElement('div'); s.className = 'sr-edit-section';
    const t = document.createElement('div'); t.className = 'sr-edit-section-title'; t.textContent = title;
    s.appendChild(t); bodyWrap.appendChild(s); return s;
  };
  const field = (parent, label, el) => {
    const wrap = document.createElement('label'); wrap.className = 'sr-edit-field';
    const lab = document.createElement('span'); lab.className = 'sr-edit-label'; lab.textContent = label;
    wrap.appendChild(lab); wrap.appendChild(el); parent.appendChild(wrap); return el;
  };
  const mkTextarea = (val, rows = 2) => { const t = document.createElement('textarea'); t.className = 'sr-edit-input'; t.rows = rows; t.value = val == null ? '' : String(val); return t; };
  const mkInput = (val, type = 'text') => { const i = document.createElement('input'); i.className = 'sr-edit-input'; i.type = type; i.value = val == null ? '' : String(val); return i; };
  const mkSelect = (options, cur) => { const s = document.createElement('select'); s.className = 'sr-edit-input'; options.forEach(o => { const op = document.createElement('option'); op.value = o; op.textContent = o; if (cur === o) op.selected = true; s.appendChild(op); }); return s; };

  const sBody = section('본문');
  const fBody = field(sBody, 'body', mkTextarea(post.body, 4));
  const fTags = field(sBody, 'hashtags (공백/쉼표 구분)', mkInput((post.hashtags || []).join(' ')));

  const media0 = (Array.isArray(post.media) && post.media[0]) ? post.media[0] : null;
  let fDesc = null; const subjectRows = [];
  if (media0) {
    const sMedia = section('미디어');
    fDesc = field(sMedia, 'media.description (이미지 프롬프트)', mkTextarea(media0.description, 3));
    const subjLabel = document.createElement('div'); subjLabel.className = 'sr-edit-label'; subjLabel.textContent = 'subjects (name / role / action)';
    sMedia.appendChild(subjLabel);
    const subjWrap = document.createElement('div'); subjWrap.className = 'sr-edit-subjects';
    (Array.isArray(media0.subjects) ? media0.subjects : []).forEach(sub => {
      const row = document.createElement('div'); row.className = 'sr-edit-subj-row';
      const n = mkInput(sub && sub.name); const r = mkSelect(['self', 'other'], sub && sub.role === 'self' ? 'self' : 'other'); const a = mkInput(sub && sub.action);
      row.append(n, r, a); subjWrap.appendChild(row); subjectRows.push({ n, r, a });
    });
    sMedia.appendChild(subjWrap);
    const ro = document.createElement('div'); ro.className = 'sr-edit-readonly';
    ro.textContent = `보존(읽기전용): status=${media0.status || '-'}, assetPath=${media0.assetPath ? '있음' : '없음'}, generatedTags=${Array.isArray(media0.generatedTags) ? media0.generatedTags.length : '-'}`;
    sMedia.appendChild(ro);
  }

  const sHidden = section('Hidden Context (디버그)');
  const hid = (post.metadata && post.metadata.hidden) || {};
  const fIntent = field(sHidden, 'intent', mkTextarea(hid.intent, 2));
  const fAudience = field(sHidden, 'audience', mkTextarea(hid.audience, 2));
  const fSubtext = field(sHidden, 'subtext', mkTextarea(hid.subtext, 2));
  const fTrigger = field(sHidden, 'triggerEvent', mkTextarea(hid.triggerEvent, 2));

  const poll = post.metadata && post.metadata.poll;
  const pollChoiceInputs = []; const pollVoteInputs = [];
  const hasPoll = poll && Array.isArray(poll.choices) && poll.choices.length > 0;
  if (hasPoll) {
    const sPoll = section('투표');
    poll.choices.forEach((c, i) => {
      const row = document.createElement('div'); row.className = 'sr-edit-subj-row';
      const ci = mkInput(c); const vi = mkInput(poll.votes ? (poll.votes[i] == null ? 0 : poll.votes[i]) : '', 'number');
      row.append(ci, vi); sPoll.appendChild(row); pollChoiceInputs.push(ci); pollVoteInputs.push(vi);
    });
  }

  const sMeta = section('메타 / 디렉터');
  const fLocation = field(sMeta, 'location', mkInput(post.metadata && post.metadata.location));
  const fCanon = field(sMeta, 'canonMode', mkSelect(['noise', 'canon', 'agent'], post.canonMode || 'noise'));
  const fMood = field(sMeta, 'mood', mkInput(post.mood));
  const fNsfw = field(sMeta, 'nsfwLevel (1-11, 빈칸=null)', mkInput(post.nsfwLevel == null ? '' : post.nsfwLevel, 'number'));
  const fDisplay = field(sMeta, 'authorDisplayName (accountId 있으면 registry 우선)', mkInput(post.authorDisplayName));

  const actions = document.createElement('div'); actions.className = 'sr-edit-actions';
  const cancel = document.createElement('button'); cancel.type = 'button'; cancel.className = 'sr-btn sr-btn-secondary'; cancel.textContent = '취소';
  const save = document.createElement('button'); save.type = 'button'; save.className = 'sr-btn sr-btn-primary'; save.textContent = '저장';
  actions.append(cancel, save); modal.appendChild(actions);

  const close = () => overlay.remove();
  cancel.addEventListener('click', close);
  overlay.addEventListener('click', (e) => { if (e.target === overlay) close(); });

  save.addEventListener('click', () => {
    const patch = {
      body: fBody.value,
      hashtags: fTags.value.split(/[\s,]+/).map(s => s.trim().replace(/^#+/, '')).filter(Boolean),
      canonMode: fCanon.value,
      mood: fMood.value.trim(),
      authorDisplayName: fDisplay.value.trim(),
    };
    const nsfwRaw = fNsfw.value.trim();
    patch.nsfwLevel = nsfwRaw === '' ? null : Number(nsfwRaw);

    const metaPatch = {};
    const hidden = { intent: fIntent.value.trim(), audience: fAudience.value.trim(), subtext: fSubtext.value.trim(), triggerEvent: fTrigger.value.trim() };
    if (Object.values(hidden).some(Boolean)) metaPatch.hidden = hidden;
    const loc = fLocation.value.trim();
    if (loc) metaPatch.location = loc;
    if (hasPoll) {
      // Keep choice/vote pairs aligned: blanking a middle choice must drop its vote too.
      const pollPairs = pollChoiceInputs
        .map((ci, i) => ({ choice: ci.value.trim(), votes: Math.max(0, Math.floor(Number(pollVoteInputs[i].value) || 0)) }))
        .filter(p => p.choice);
      metaPatch.poll = { choices: pollPairs.map(p => p.choice), votes: pollPairs.map(p => p.votes) };
    }
    if (Object.keys(metaPatch).length) patch.metadata = metaPatch;

    if (media0) {
      patch.media = {
        description: fDesc.value,
        subjects: subjectRows.map(r => ({ name: r.n.value.trim(), role: r.r.value, action: r.a.value.trim() })).filter(s => s.name),
      };
    }

    pm.updatePostFields(post.id, patch);
    close();
    if (typeof onSaved === 'function') onSaved();
  });

  (document.querySelector('.sr-app') || document.body).appendChild(overlay);
}

