    container.appendChild(style);

    const feed = document.createElement('div');
    feed.className = 'sr-feed';

    // Toolbar
    const toolbar = document.createElement('div');
    toolbar.className = 'sr-feed-toolbar';

    const platforms = [
      { id: null, label: 'All' },
      { id: 'twitter', label: 'Twitter' },
      { id: 'instagram', label: 'Insta' },
    ];

    if (!this._hideFilterToolbar) {
      for (const p of platforms) {
        const btn = document.createElement('button');
        btn.className = 'sr-feed-filter' + (p.id === this.activePlatform ? ' active' : '');
        btn.textContent = p.label;
        btn.addEventListener('click', () => {
          this.activePlatform = p.id;
          this.render(container);
        });
        toolbar.appendChild(btn);
      }
    }

    const refreshBtn = document.createElement('button');
    refreshBtn.className = 'sr-feed-gen-btn';
    refreshBtn.style.background = 'rgba(255,200,50,0.6)';
    refreshBtn.textContent = '🕐';
    refreshBtn.title = 'Refresh timeline (generate missed posts)';
    refreshBtn.addEventListener('click', async () => {
      if (!this.onRefreshTimeline) return;
      refreshBtn.disabled = true;
      refreshBtn.textContent = '⏳';
      try {
        const result = await this.onRefreshTimeline();
        this._renderPosts(feedList);
        if (result && result.length > 0) {
          this._showAwayCard(feedList, result.length);
        }
      } catch (e) {
        console.error('[sns_nai] Refresh error:', e.message);
      }
      refreshBtn.disabled = false;
      refreshBtn.textContent = '🕐';
    });
    toolbar.appendChild(refreshBtn);

    const dirToggle = document.createElement('button');
    dirToggle.className = 'sr-feed-gen-btn';
    dirToggle.textContent = this.directorOpen ? '◀ 디렉터' : '▶ 디렉터';
    dirToggle.style.marginLeft = 'auto';
    dirToggle.addEventListener('click', () => {
      this.directorOpen = !this.directorOpen;
      this.render(container);
    });
    toolbar.appendChild(dirToggle);

    // Layout: sidebar + feed
    const layout = document.createElement('div');
    layout.className = 'sr-feed-layout';
    layout.style.flex = '1';

    // Director sidebar
    if (this.directorOpen) {
      const sidebar = this._buildDirectorSidebar(container);
      layout.appendChild(sidebar);
    }

    // Feed main
    const feedMain = document.createElement('div');
    feedMain.className = 'sr-feed-main';
    feedMain.appendChild(toolbar);

    const feedList = document.createElement('div');
    feedList.className = 'sr-feed-list';
