    this.igView.onGetCurStamp = _curStampCb;
    this.ofView.onGetCurStamp = _curStampCb;
    await this._refreshAndPersistUserAccountIds();
    await this._migrateAutoFollowEdges();
    this._migrateAutoFollowTiersV2();
