    this.xView.onOpenDirector = () => this._openDirector();
    this.xView.onToast = (message, opts) => this.showToast(message, opts);
    this.xView.onRegenerateImage = async (postId) => this.generator.regenerateImage(postId);
    this.xView.onRerollImage = async (postId) => this.generator.rerollImage(postId);
